def check_drug_interactions(drugs):
    """
    检查药物相互作用（基于本地知识库）。

    参数：
    - drugs: 药物名称列表，如 ["Warfarin", "Aspirin"]

    返回：
    - input_drugs: 输入的药物列表（小写）
    - interaction_count: 发现的相互作用数量
    - interactions: 相互作用详情列表
    - status: "Safe"（无相互作用）或 "Alert"（有相互作用）
    """
    # 本地 DDI 数据库（来自原始 impl.py）
    ddi_db = {
        ("aspirin", "warfarin"): {
            "severity": "Major",
            "mechanism": "Pharmacodynamic synergism",
            "effect": "Increased risk of bleeding.",
            "recommendation": "Avoid concurrent use or monitor INR closely."
        },
        ("lisinopril", "potassium chloride"): {
            "severity": "Major",
            "mechanism": "Additive hyperkalemic effect",
            "effect": "Risk of severe hyperkalemia.",
            "recommendation": "Monitor serum potassium."
        },
        ("atorvastatin", "clarithromycin"): {
            "severity": "Major",
            "mechanism": "CYP3A4 inhibition",
            "effect": "Increased risk of myopathy/rhabdomyolysis.",
            "recommendation": "Avoid combination or limit statin dose."
        },
        ("nitroglycerin", "sildenafil"): {
            "severity": "Severe/Contraindicated",
            "mechanism": "Vasodilation synergism",
            "effect": "Profound hypotension.",
            "recommendation": "Contraindicated."
        }
    }

    # 标准化药物名称
    drugs = [d.lower().strip() for d in drugs]
    interactions = []

    # 检查所有药物对
    for i in range(len(drugs)):
        for j in range(i + 1, len(drugs)):
            pair = tuple(sorted((drugs[i], drugs[j])))

            if pair in ddi_db:
                info = ddi_db[pair]
                interactions.append({
                    "drug_1": pair[0],
                    "drug_2": pair[1],
                    "severity": info["severity"],
                    "effect": info["effect"],
                    "recommendation": info["recommendation"]
                })

    return {
        "input_drugs": drugs,
        "interaction_count": len(interactions),
        "interactions": interactions,
        "status": "Safe" if len(interactions) == 0 else "Alert"
    }

def triage_message(message):
    """
    对患者门户消息进行分诊，识别紧急程度并推荐路由。

    参数：
    - message: 消息字典，包含以下字段：
      - message_id: 消息 ID
      - patient_id: 患者 ID
      - subject: 主题
      - content: 消息内容
      - patient_flags: 患者标志（可选），如 {"high_risk": True, "cardiac_history": True}

    返回：
    - message_id: 消息 ID
    - patient_id: 患者 ID
    - urgency_level: 紧急程度（emergent/urgent/routine/low）
    - urgency_score: 紧急评分（0-100）
    - category: 消息类别
    - routing: 路由信息（primary_route, escalation_route）
    - response_recommendation: 响应建议
    - suggested_response_time: 建议响应时间
    """
    from datetime import datetime

    # 紧急关键词库
    urgency_keywords = {
        "emergent": [
            "chest pain", "difficulty breathing", "shortness of breath",
            "severe bleeding", "stroke symptoms", "suicidal", "overdose",
            "unresponsive", "seizure", "allergic reaction", "anaphylaxis",
        ],
        "urgent": [
            "fever over 101", "severe pain", "worsening symptoms",
            "new rash", "swelling", "dizziness", "fainting",
            "blood in urine", "blood in stool", "severe headache",
            "medication reaction", "can't keep food down",
        ],
        "routine": [
            "refill", "refill request", "lab results", "appointment",
            "follow-up", "chronic condition", "routine question",
        ],
    }

    # 路由规则
    routing_rules = {
        "symptoms": {
            "primary_route": "nursing_triage",
            "escalation": "provider_review",
        },
        "medication": {
            "primary_route": "pharmacy",
            "escalation": "provider_review",
        },
        "appointment": {
            "primary_route": "scheduling",
            "escalation": None,
        },
        "results": {
            "primary_route": "provider_review",
            "escalation": None,
        },
        "referral": {
            "primary_route": "care_coordinator",
            "escalation": "provider_review",
        },
        "mental_health": {
            "primary_route": "behavioral_health",
            "escalation": "crisis_team",
        },
        "billing": {
            "primary_route": "billing_dept",
            "escalation": None,
        },
    }

    content = message.get("content", "").lower()
    subject = message.get("subject", "").lower()
    patient_flags = message.get("patient_flags", {})

    # 评估紧急程度
    urgency_level = "low"
    urgency_score = 0
    matched_keywords = []

    for level, keywords in urgency_keywords.items():
        for keyword in keywords:
            if keyword in content or keyword in subject:
                matched_keywords.append(keyword)
                if level == "emergent":
                    urgency_level = "emergent"
                    urgency_score = max(urgency_score, 90)
                elif level == "urgent" and urgency_level != "emergent":
                    urgency_level = "urgent"
                    urgency_score = max(urgency_score, 70)
                elif level == "routine" and urgency_level not in ["emergent", "urgent"]:
                    urgency_level = "routine"
                    urgency_score = max(urgency_score, 40)

    # 患者标志加权
    if patient_flags.get("high_risk") and urgency_level in ["urgent", "routine"]:
        urgency_score += 10
    if patient_flags.get("cardiac_history") and any(k in ["chest pain", "shortness of breath"] for k in matched_keywords):
        urgency_level = "emergent"
        urgency_score = 95

    # 分类消息
    category = "administrative"
    if any(k in content or k in subject for k in ["anxious", "depressed", "suicidal", "mental"]):
        category = "mental_health"
    elif any(k in content or k in subject for k in ["pain", "symptom", "feel", "sick", "hurt"]):
        category = "symptoms"
    elif any(k in content or k in subject for k in ["medication", "refill", "prescription", "drug"]):
        category = "medication"
    elif any(k in content or k in subject for k in ["appointment", "schedule", "visit"]):
        category = "appointment"
    elif any(k in content or k in subject for k in ["result", "lab", "test"]):
        category = "results"
    elif any(k in content or k in subject for k in ["referral", "specialist"]):
        category = "referral"
    elif any(k in content or k in subject for k in ["bill", "payment", "insurance", "charge"]):
        category = "billing"

    # 确定路由
    routing_info = routing_rules.get(category, {"primary_route": "general_inbox", "escalation": None})

    # 生成响应建议
    if urgency_level == "emergent":
        response_recommendation = "立即联系患者，考虑建议急诊就诊或拨打 911"
        suggested_response_time = "立即（15 分钟内）"
    elif urgency_level == "urgent":
        response_recommendation = "当日内联系患者，评估是否需要当日就诊"
        suggested_response_time = "当日内（4 小时内）"
    elif urgency_level == "routine":
        response_recommendation = "标准响应流程，提供所需信息或安排随访"
        suggested_response_time = "24-48 小时内"
    else:
        response_recommendation = "常规处理，提供信息或转发至相关部门"
        suggested_response_time = "48-72 小时内"

    return {
        "message_id": message.get("message_id", "unknown"),
        "patient_id": message.get("patient_id", "unknown"),
        "urgency_level": urgency_level,
        "urgency_score": urgency_score,
        "category": category,
        "matched_keywords": matched_keywords,
        "routing": {
            "primary_route": routing_info["primary_route"],
            "escalation_route": routing_info["escalation"]
        },
        "response_recommendation": response_recommendation,
        "suggested_response_time": suggested_response_time,
        "triaged_at": datetime.utcnow().isoformat()
    }

def process_appeal(claim, denial_reason, clinical_records, appeal_type="first_level"):
    """
    处理保险索赔申诉，生成申诉信和证据分析。

    参数：
    - claim: 索赔信息字典，包含：
      - claim_id: 索赔 ID
      - patient_name: 患者姓名
      - procedure_code: 手术/检查代码
      - procedure_name: 手术/检查名称
      - service_date: 服务日期
    - denial_reason: 拒赔原因（medical_necessity/experimental_investigational/out_of_network等）
    - clinical_records: 临床记录列表，每项包含 type/provider/date/findings 或 test/result/abnormal
    - appeal_type: 申诉类型（first_level/second_level/external_review/expedited）

    返回：
    - claim_id: 索赔 ID
    - appeal_type: 申诉类型
    - denial_reason: 拒赔原因
    - recommendation: 申诉建议（STRONG_APPEAL/MODERATE_APPEAL/WEAK_APPEAL）
    - evidence_strength: 证据强度（HIGH/MODERATE/LOW）
    - appeal_letter: 生成的申诉信
    - supporting_documents: 所需支持文档列表
    """
    from datetime import datetime

    # 临床指南数据库
    guideline_db = {
        "MRI-LUMBAR": {
            "source": "ACR Appropriateness Criteria",
            "indications": [
                "Radiculopathy with motor deficit",
                "Cauda equina syndrome suspected",
                "Failed conservative therapy > 6 weeks",
                "Post-surgical evaluation",
            ],
            "evidence_level": "Usually Appropriate",
        },
        "BIOLOGICS-RA": {
            "source": "ACR/AAFP Guidelines 2021",
            "indications": [
                "Moderate-to-high disease activity despite csDMARD",
                "Poor prognostic factors present",
                "Contraindication to methotrexate",
            ],
            "evidence_level": "Strong Recommendation",
        },
        "GENETIC-TESTING-BRCA": {
            "source": "NCCN Guidelines v3.2024",
            "indications": [
                "Personal history of breast cancer < 50",
                "Family history meeting criteria",
                "Ashkenazi Jewish ancestry with breast/ovarian cancer",
                "Male breast cancer",
            ],
            "evidence_level": "Category 1",
        },
    }

    # 覆盖政策数据库
    policy_db = {
        "CMS-LCD-L35050": {
            "title": "MRI of the Spine",
            "criteria": [
                "Documentation of failed conservative therapy",
                "Neurological examination findings",
                "Specific clinical indication documented",
            ],
        },
        "CMS-NCD-110.21": {
            "title": "Genetic Testing for BRCA",
            "criteria": [
                "Family history assessment completed",
                "Risk assessment tool utilized",
                "Genetic counseling provided",
            ],
        },
    }

    # 提取临床证据
    findings = []
    for record in clinical_records:
        if record.get("type") == "clinical_note":
            findings.append({
                "source": record.get("provider", "Unknown"),
                "date": record.get("date", ""),
                "key_findings": record.get("findings", []),
                "supports_necessity": True,
            })
        elif record.get("type") == "lab_result":
            findings.append({
                "source": "Laboratory",
                "date": record.get("date", ""),
                "key_findings": [f"{record.get('test')}: {record.get('result')}"],
                "supports_necessity": record.get("abnormal", False),
            })

    # 匹配临床指南
    procedure = claim.get("procedure_code", "")
    guideline = None
    matched_indications = []

    for key, value in guideline_db.items():
        if key in procedure or procedure in key:
            guideline = value
            for indication in guideline.get("indications", []):
                for finding in findings:
                    if any(indication.lower() in f.lower() for f in finding.get("key_findings", [])):
                        matched_indications.append(indication)
                        break
            break

    guideline_source = guideline.get("source") if guideline else None
    evidence_level = guideline.get("evidence_level") if guideline else None
    coverage_supported = len(matched_indications) > 0

    # 分析覆盖政策
    met_criteria = []
    unmet_criteria = []
    for policy_id, policy in policy_db.items():
        for criterion in policy.get("criteria", []):
            criterion_met = any(criterion.lower() in str(f).lower() for f in findings)
            if criterion_met:
                met_criteria.append(criterion)
            else:
                unmet_criteria.append(criterion)

    policy_compliance = len(met_criteria) / max(len(met_criteria) + len(unmet_criteria), 1)

    # 确定申诉建议
    score = 0
    if len(findings) >= 2:
        score += 1
    if coverage_supported:
        score += 2
    if policy_compliance >= 0.5:
        score += 1

    if score >= 3:
        recommendation = "STRONG_APPEAL"
    elif score >= 2:
        recommendation = "MODERATE_APPEAL"
    else:
        recommendation = "WEAK_APPEAL"

    # 计算证据强度
    if evidence_level in ["Category 1", "Strong Recommendation"]:
        evidence_strength = "HIGH"
    elif len(findings) >= 3:
        evidence_strength = "MODERATE"
    else:
        evidence_strength = "LOW"

    # 生成申诉信
    evidence_text = []
    for finding in findings:
        evidence_text.append(f"- {finding.get('source')} ({finding.get('date')}): {', '.join(finding.get('key_findings', []))}")
    evidence_section = "\n".join(evidence_text) if evidence_text else "See attached clinical documentation."

    guideline_section = ""
    if coverage_supported:
        guideline_section = f"Per {guideline_source}, this service meets criteria with {evidence_level} recommendation."
    else:
        guideline_section = "Clinical documentation supports medical necessity."

    policy_section = f"Coverage criteria compliance: {policy_compliance:.0%}"

    appeal_letter = f"""
APPEAL FOR CLAIM {claim.get('claim_id')}

RE: Request for Reconsideration - {claim.get('procedure_name', 'Medical Service')}
Patient: {claim.get('patient_name', '[Patient Name]')}
Date of Service: {claim.get('service_date', '[Date]')}
Denial Reason: {denial_reason}

Dear Claims Review Committee,

We are writing to appeal the denial of the above-referenced claim. Based on our
review of the clinical documentation and applicable guidelines, we believe this
service meets medical necessity criteria.

CLINICAL EVIDENCE:
{evidence_section}

GUIDELINE SUPPORT:
{guideline_section}

COVERAGE POLICY COMPLIANCE:
{policy_section}

Based on the above evidence, we respectfully request that this claim be
reconsidered and approved for payment.

Sincerely,
[Provider Name]
"""

    # 列出所需文档
    base_docs = [
        "Clinical notes from treating physician",
        "Relevant diagnostic test results",
        "Prior authorization documentation (if applicable)",
    ]

    if denial_reason == "medical_necessity":
        base_docs.extend([
            "Letter of medical necessity",
            "Peer-reviewed literature supporting treatment",
        ])
    elif denial_reason == "experimental_investigational":
        base_docs.extend([
            "FDA approval documentation",
            "Clinical trial results",
            "Compendia citations",
        ])

    return {
        "claim_id": claim.get("claim_id", "unknown"),
        "appeal_type": appeal_type,
        "denial_reason": denial_reason,
        "recommendation": recommendation,
        "evidence_strength": evidence_strength,
        "appeal_letter": appeal_letter,
        "supporting_documents": base_docs,
        "matched_indications": matched_indications,
        "policy_compliance": policy_compliance,
        "generated_at": datetime.utcnow().isoformat()
    }

def analyze_wearable_health_data(user_data):
    """
    分析可穿戴设备健康数据，检测趋势和异常，提供个性化健康建议。

    参数：
    - user_data: 用户健康数据字典，包含：
      - user_id: 用户 ID
      - resting_heart_rate: 静息心率列表（bpm）
      - sleep_quality_score: 睡眠质量评分列表（0-100）
      - activity_minutes: 活动时长列表（分钟，可选）
      - steps: 步数列表（可选）

    返回：
    - user_id: 用户 ID
    - insights: 洞察列表，每项包含 type/metric/message/advice
    - summary: 总结
    - trends: 趋势分析结果
    """
    import statistics

    # 警报阈值
    alert_thresholds = {
        "resting_heart_rate_increase": 5,  # bpm 增加
        "sleep_score_decrease": 10,        # 百分比下降
        "activity_decrease": 30,           # 分钟下降
        "steps_decrease": 2000             # 步数下降
    }

    insights = []
    trends = {}

    # 趋势分析辅助函数
    def analyze_trend(data_points):
        """简单线性回归斜率检测趋势方向"""
        if len(data_points) < 2:
            return {"slope": 0, "change": 0, "direction": "stable"}

        first_avg = statistics.mean(data_points[:3]) if len(data_points) >= 3 else data_points[0]
        last_avg = statistics.mean(data_points[-3:]) if len(data_points) >= 3 else data_points[-1]

        change = last_avg - first_avg
        slope = change / len(data_points)

        if abs(change) < 1:
            direction = "stable"
        elif change > 0:
            direction = "increasing"
        else:
            direction = "decreasing"

        return {"slope": slope, "change": change, "direction": direction}

    # 1. 静息心率分析
    rhr_data = user_data.get("resting_heart_rate", [])
    if rhr_data:
        rhr_trend = analyze_trend(rhr_data)
        trends["resting_heart_rate"] = rhr_trend

        if rhr_trend["slope"] > 0 and rhr_trend["change"] > alert_thresholds["resting_heart_rate_increase"]:
            insights.append({
                "type": "ALERT",
                "metric": "Resting Heart Rate",
                "message": f"您的静息心率在本周增加了 {rhr_trend['change']:.1f} bpm",
                "advice": "这可能表明压力、疾病发展或过度训练。建议今晚优先保证睡眠。",
                "severity": "high"
            })
        elif rhr_trend["slope"] < 0 and abs(rhr_trend["change"]) > 3:
            insights.append({
                "type": "INFO",
                "metric": "Resting Heart Rate",
                "message": f"您的静息心率下降了 {abs(rhr_trend['change']):.1f} bpm",
                "advice": "这通常是心血管健康改善的积极信号。继续保持！",
                "severity": "low"
            })

    # 2. 睡眠质量分析
    sleep_data = user_data.get("sleep_quality_score", [])
    if sleep_data:
        sleep_trend = analyze_trend(sleep_data)
        trends["sleep_quality"] = sleep_trend

        if sleep_trend["slope"] < 0 and abs(sleep_trend["change"]) > alert_thresholds["sleep_score_decrease"]:
            insights.append({
                "type": "WARNING",
                "metric": "Sleep Quality",
                "message": f"您的睡眠质量显著下降了 {abs(sleep_trend['change']):.1f} 分",
                "advice": "避免下午 2 点后摄入咖啡因，尝试保持固定的就寝时间。",
                "severity": "medium"
            })
        elif sleep_trend["slope"] > 0 and sleep_trend["change"] > 5:
            insights.append({
                "type": "INFO",
                "metric": "Sleep Quality",
                "message": f"您的睡眠质量改善了 {sleep_trend['change']:.1f} 分",
                "advice": "继续保持当前的睡眠习惯！",
                "severity": "low"
            })

    # 3. 活动时长分析
    activity_data = user_data.get("activity_minutes", [])
    if activity_data:
        activity_trend = analyze_trend(activity_data)
        trends["activity_minutes"] = activity_trend

        if activity_trend["slope"] < 0 and abs(activity_trend["change"]) > alert_thresholds["activity_decrease"]:
            insights.append({
                "type": "WARNING",
                "metric": "Activity Level",
                "message": f"您的活动时长减少了 {abs(activity_trend['change']):.0f} 分钟",
                "advice": "尝试每天增加 10-15 分钟的轻度活动，如散步。",
                "severity": "medium"
            })

    # 4. 步数分析
    steps_data = user_data.get("steps", [])
    if steps_data:
        steps_trend = analyze_trend(steps_data)
        trends["steps"] = steps_trend

        if steps_trend["slope"] < 0 and abs(steps_trend["change"]) > alert_thresholds["steps_decrease"]:
            insights.append({
                "type": "INFO",
                "metric": "Daily Steps",
                "message": f"您的日均步数减少了 {abs(steps_trend['change']):.0f} 步",
                "advice": "考虑设置每日步数目标，逐步增加活动量。",
                "severity": "low"
            })

    # 5. 综合健康评分
    health_score = 100
    for insight in insights:
        if insight["severity"] == "high":
            health_score -= 15
        elif insight["severity"] == "medium":
            health_score -= 10
        elif insight["severity"] == "low":
            health_score -= 5

    # 生成总结
    if not insights:
        summary = "您的健康指标看起来很稳定。继续保持良好的工作！"
    else:
        alert_count = len([i for i in insights if i["type"] == "ALERT"])
        warning_count = len([i for i in insights if i["type"] == "WARNING"])
        summary = f"在您最近的数据中发现了 {len(insights)} 个潜在问题（{alert_count} 个警报，{warning_count} 个警告）。请查看下面的详细信息。"

    return {
        "user_id": user_data.get("user_id", "unknown"),
        "insights": insights,
        "summary": summary,
        "trends": trends,
        "health_score": max(0, health_score),
        "analyzed_metrics": list(trends.keys())
    }

def search_drugbank(query, max_results=10):
    """
    在 DrugBank 数据库中搜索药物信息（通过 Valyu API）。

    参数：
    - query: 搜索查询（自然语言）
    - max_results: 返回的最大结果数（默认 10）

    返回：
    - success: 是否成功
    - query: 搜索查询
    - result_count: 结果数量
    - results: 结果列表，每个包含 title/url/content/source/relevance_score/images
    - cost: API 调用成本
    - error: 错误信息（如果有）
    - setup_required: 是否需要设置 API Key
    """
    import os
    import requests

    VALYU_API_BASE = "https://api.valyu.ai/v1"

    # 获取 API Key（从环境变量）
    api_key = os.environ.get("VALYU_API_KEY")

    if not api_key:
        return {
            "success": False,
            "setup_required": True,
            "message": "Valyu API key not configured. Set VALYU_API_KEY environment variable. Get your free API key ($10 credits) at https://platform.valyu.ai"
        }

    try:
        response = requests.post(
            f"{VALYU_API_BASE}/search",
            headers={
                "Content-Type": "application/json",
                "x-api-key": api_key
            },
            json={
                "query": query,
                "search_type": "proprietary",
                "included_sources": ["valyu/valyu-drugbank"],
                "limit": max_results
            },
            timeout=30
        )

        data = response.json()

        if not response.ok:
            return {
                "success": False,
                "error": data.get("detail") or data.get("message") or f"HTTP {response.status_code}",
                "status": response.status_code
            }

        return {
