def query_datacommons(entity_names, variable_dcids, date="latest", entity_type=None):
    """
    查询 Data Commons 公共统计数据（人口、经济、健康、环境等）。

    参数：
    - entity_names: 实体名称列表（如 ["California", "Texas"]）
    - variable_dcids: 统计变量 DCID 列表（如 ["Count_Person", "UnemploymentRate_Person"]）
    - date: 日期（"latest" 或 "all" 或具体年份如 "2020"），默认 "latest"
    - entity_type: 实体类型（如 "State", "County", "Country"），用于消歧

    返回：
    - success: 是否成功
    - entity_names: 输入的实体名称
    - variable_dcids: 输入的统计变量
    - resolved_entities: 解析后的实体 DCID 列表
    - observations: 观测数据列表，每个包含 entity/variable/date/value
    - error: 错误信息（如果有）
    - setup_required: 是否需要安装依赖
    """
    try:
        from datacommons_client import DataCommonsClient
    except ImportError:
        return {
            "success": False,
            "setup_required": True,
            "message": "datacommons-client not installed. Install with: pip install datacommons-client"
        }

    try:
        client = DataCommonsClient()

        # 步骤 1：解析实体名称为 DCID
        resolve_response = client.resolve.fetch_dcids_by_name(
            names=entity_names,
            entity_type=entity_type
        )

        resolved_dict = resolve_response.to_dict()
        dcids = []
        resolved_entities = []

        for name in entity_names:
            if name in resolved_dict and resolved_dict[name].get("candidates"):
                dcid = resolved_dict[name]["candidates"][0]["dcid"]
                dcids.append(dcid)
                resolved_entities.append({
                    "name": name,
                    "dcid": dcid
                })
            else:
                resolved_entities.append({
                    "name": name,
                    "dcid": None,
                    "error": "无法解析"
                })

        if not dcids:
            return {
                "success": False,
                "error": "无法解析任何实体名称",
                "entity_names": entity_names,
                "resolved_entities": resolved_entities
            }

        # 步骤 2：查询统计数据
        obs_response = client.observation.fetch(
            variable_dcids=variable_dcids,
            entity_dcids=dcids,
            date=date
        )

        # 转换为记录格式
        observations = []
        obs_dict = obs_response.to_dict()

        for entity_dcid, entity_data in obs_dict.items():
            entity_name = next((e["name"] for e in resolved_entities if e["dcid"] == entity_dcid), entity_dcid)
            for var_dcid, var_data in entity_data.items():
                if "observations" in var_data:
                    for obs in var_data["observations"]:
                        observations.append({
                            "entity": entity_name,
                            "entity_dcid": entity_dcid,
                            "variable": var_dcid,
                            "date": obs.get("date"),
                            "value": obs.get("value")
                        })

        return {
            "success": True,
            "type": "datacommons_query",
            "entity_names": entity_names,
            "variable_dcids": variable_dcids,
            "resolved_entities": resolved_entities,
            "observation_count": len(observations),
            "observations": observations
        }

    except Exception as e:
        return {
            "success": False,
            "error": str(e)
        }

def validate_fhir_resource(resource_type, resource_data):
    """
    验证 FHIR R4 资源的必填字段和枚举值。

    参数：
    - resource_type: 资源类型（如 "Patient", "Observation", "Encounter" 等）
    - resource_data: 资源数据（dict）

    返回：
    - valid: 是否有效
    - resource_type: 资源类型
    - errors: 错误列表（如果有）
    - warnings: 警告列表（如果有）
    """
    errors = []
    warnings = []

    # 验证 resourceType 字段
    if resource_data.get("resourceType") != resource_type:
        errors.append(f"resourceType 必须为 '{resource_type}'，实际为 '{resource_data.get('resourceType')}'")

    # 按资源类型验证必填字段和枚举值
    if resource_type == "Patient":
        # Patient 没有必填字段
        if "gender" in resource_data:
            valid_genders = {"male", "female", "other", "unknown"}
            if resource_data["gender"] not in valid_genders:
                errors.append(f"Patient.gender 必须是 {valid_genders} 之一，实际为 '{resource_data['gender']}'")

    elif resource_type == "Observation":
        # 必填字段：status, code
        if not resource_data.get("status"):
            errors.append("Observation.status 是必填字段")
        else:
            valid_status = {"registered", "preliminary", "final", "amended", "corrected", "cancelled", "entered-in-error", "unknown"}
            if resource_data["status"] not in valid_status:
                errors.append(f"Observation.status 必须是 {valid_status} 之一，实际为 '{resource_data['status']}'")

        if not resource_data.get("code"):
            errors.append("Observation.code 是必填字段")

    elif resource_type == "Encounter":
        # 必填字段：status, class
        if not resource_data.get("status"):
            errors.append("Encounter.status 是必填字段")
        else:
            valid_status = {"planned", "arrived", "triaged", "in-progress", "onleave", "finished", "cancelled", "entered-in-error", "unknown"}
            if resource_data["status"] not in valid_status:
                errors.append(f"Encounter.status 必须是 {valid_status} 之一，实际为 '{resource_data['status']}'")

        if not resource_data.get("class"):
            errors.append("Encounter.class 是必填字段")

    elif resource_type == "Condition":
        # 必填字段：subject
        if not resource_data.get("subject"):
            errors.append("Condition.subject 是必填字段")

        if "clinicalStatus" in resource_data:
            valid_clinical = {"active", "recurrence", "relapse", "inactive", "remission", "resolved"}
            clinical_status = resource_data["clinicalStatus"]
            # clinicalStatus 可能是 CodeableConcept
            if isinstance(clinical_status, dict):
                if "coding" in clinical_status and clinical_status["coding"]:
                    code = clinical_status["coding"][0].get("code")
                    if code and code not in valid_clinical:
                        errors.append(f"Condition.clinicalStatus 必须是 {valid_clinical} 之一，实际为 '{code}'")
            elif isinstance(clinical_status, str) and clinical_status not in valid_clinical:
                errors.append(f"Condition.clinicalStatus 必须是 {valid_clinical} 之一，实际为 '{clinical_status}'")

    elif resource_type == "MedicationRequest":
        # 必填字段：status, intent, medication[x], subject
        if not resource_data.get("status"):
            errors.append("MedicationRequest.status 是必填字段")
        else:
            valid_status = {"active", "on-hold", "cancelled", "completed", "entered-in-error", "stopped", "draft", "unknown"}
            if resource_data["status"] not in valid_status:
                errors.append(f"MedicationRequest.status 必须是 {valid_status} 之一，实际为 '{resource_data['status']}'")

        if not resource_data.get("intent"):
            errors.append("MedicationRequest.intent 是必填字段")
        else:
            valid_intent = {"proposal", "plan", "order", "original-order", "reflex-order", "filler-order", "instance-order", "option"}
            if resource_data["intent"] not in valid_intent:
                errors.append(f"MedicationRequest.intent 必须是 {valid_intent} 之一，实际为 '{resource_data['intent']}'")

        # medication[x] - 可以是 medicationCodeableConcept 或 medicationReference
        if not (resource_data.get("medicationCodeableConcept") or resource_data.get("medicationReference")):
            errors.append("MedicationRequest.medication[x] 是必填字段（medicationCodeableConcept 或 medicationReference）")

        if not resource_data.get("subject"):
            errors.append("MedicationRequest.subject 是必填字段")

    elif resource_type == "Bundle":
        # 必填字段：type
        if not resource_data.get("type"):
            errors.append("Bundle.type 是必填字段")
        else:
            valid_types = {"document", "message", "transaction", "transaction-response", "batch", "batch-response", "history", "searchset", "collection"}
            if resource_data["type"] not in valid_types:
                errors.append(f"Bundle.type 必须是 {valid_types} 之一，实际为 '{resource_data['type']}'")

    else:
        warnings.append(f"资源类型 '{resource_type}' 的验证规则未实现，仅进行基本检查")

    return {
        "valid": len(errors) == 0,
        "resource_type": resource_type,
        "errors": errors if errors else None,
        "warnings": warnings if warnings else None,
        "http_status": 422 if errors else 200,
        "http_status_text": "Unprocessable Entity" if errors else "OK"
    }

def extract_wsi_info(slide_path, output_path=None):
    """
    读取全切片图像（WSI）并提取基本信息。

    参数：
    - slide_path: WSI 文件路径（.svs, .tiff, .ndpi 等）
    - output_path: 输出目录（可选，用于保存缩略图）

    返回：
    - success: 是否成功
    - slide_path: 文件路径
    - dimensions: 图像尺寸（宽, 高）
    - levels: 金字塔层级数
    - level_dimensions: 各层级尺寸列表
    - properties: 图像属性（放大倍数等）
    - thumbnail_saved: 是否保存了缩略图
    - error: 错误信息（如果有）
    - setup_required: 是否需要安装依赖
    """
    try:
        from histolab.slide import Slide
    except ImportError:
        return {
            "success": False,
            "setup_required": True,
            "message": "histolab not installed. Install with: pip install histolab"
        }

    import os
    import tempfile

    try:
        # 如果未指定输出路径，使用临时目录
        if output_path is None:
            output_path = tempfile.mkdtemp()

        # 加载 WSI
        slide = Slide(slide_path, processed_path=output_path)

        # 提取基本信息
        dimensions = slide.dimensions
        levels = slide.levels

        # 各层级尺寸
        level_dimensions = []
        try:
            for level in range(len(levels)):
                level_dimensions.append(slide.level_dimensions(level))
        except Exception:
            pass

        # 图像属性
        properties = {}
        try:
            props = slide.properties
            if props:
                for key, value in props.items():
                    properties[str(key)] = str(value)
        except Exception:
            pass

        # 保存缩略图
        thumbnail_saved = False
        try:
            slide.save_thumbnail()
            thumbnail_saved = True
        except Exception:
            pass

        return {
            "success": True,
            "type": "wsi_info",
            "slide_path": slide_path,
            "slide_name": slide.name,
            "dimensions": dimensions,
            "levels": len(levels) if levels else 0,
            "level_dimensions": level_dimensions,
            "properties": properties,
            "output_path": output_path,
            "thumbnail_saved": thumbnail_saved
        }

    except FileNotFoundError:
        return {
            "success": False,
            "error": f"文件不存在: {slide_path}"
        }
    except Exception as e:
        return {
            "success": False,
            "error": str(e),
            "slide_path": slide_path
        }

def analyze_diagnostic_reasoning(case_data, check_biases=True):
    """
    分析临床诊断推理中的认知偏差，提供改进建议。

    参数:
        case_data (dict): 病例数据，包含以下字段:
            - chief_complaint (str): 主诉
            - history (str): 病史
            - exam_findings (str): 体格检查发现
            - initial_diagnosis (str): 初步诊断
            - differential_diagnoses (list): 鉴别诊断列表
        check_biases (bool): 是否检查认知偏差，默认为 True

    返回:
        dict: 包含以下字段:
            - cognitive_biases_detected (list): 检测到的认知偏差列表
            - bias_analysis (dict): 各偏差的详细分析
            - recommendations (list): 改进建议
            - differential_completeness_score (float): 鉴别诊断完整性评分 (0-1)
    """
    cognitive_biases_detected = []
    bias_analysis = {}
    recommendations = []

    chief_complaint = case_data.get("chief_complaint", "")
    history = case_data.get("history", "")
    exam_findings = case_data.get("exam_findings", "")
    initial_diagnosis = case_data.get("initial_diagnosis", "")
    differential_diagnoses = case_data.get("differential_diagnoses", [])

    # 计算鉴别诊断完整性评分
    # 理想情况下应有 3-5 个鉴别诊断
    diff_count = len(differential_diagnoses)
    if diff_count == 0:
        differential_completeness_score = 0.0
    elif diff_count == 1:
        differential_completeness_score = 0.3
    elif diff_count == 2:
        differential_completeness_score = 0.6
    elif diff_count <= 5:
        differential_completeness_score = 0.8 + (diff_count - 3) * 0.05
        differential_completeness_score = min(1.0, differential_completeness_score)
    else:
        # 超过 5 个可能表示缺乏聚焦
        differential_completeness_score = max(0.7, 1.0 - (diff_count - 5) * 0.05)

    if not check_biases:
        return {
            "cognitive_biases_detected": [],
            "bias_analysis": {},
            "recommendations": ["已跳过认知偏差检查"],
            "differential_completeness_score": differential_completeness_score
        }

    # 检查锚定偏差 (Anchoring Bias)
    # 如果鉴别诊断列表中初步诊断占主导地位（只有1个或初步诊断与第一个鉴别诊断相同）
    if diff_count <= 1:
        cognitive_biases_detected.append("锚定偏差 (Anchoring Bias)")
        bias_analysis["锚定偏差"] = {
            "detected": True,
            "evidence": f"鉴别诊断数量不足（{diff_count} 个），可能过早锚定于初步诊断",
            "severity": "高"
        }
        recommendations.append("扩展鉴别诊断列表，至少考虑 3-5 个可能诊断，避免过早锚定")
    else:
        bias_analysis["锚定偏差"] = {"detected": False, "evidence": "鉴别诊断数量充足", "severity": "低"}

    # 检查过早闭合偏差 (Premature Closure)
    # 如果初步诊断与第一个鉴别诊断完全相同，且鉴别诊断列表较短
    if differential_diagnoses and initial_diagnosis:
        first_diff = differential_diagnoses[0].lower() if differential_diagnoses else ""
        initial_lower = initial_diagnosis.lower()
        if first_diff == initial_lower and diff_count < 3:
            cognitive_biases_detected.append("过早闭合偏差 (Premature Closure)")
            bias_analysis["过早闭合偏差"] = {
                "detected": True,
                "evidence": "初步诊断与首个鉴别诊断相同，且鉴别诊断列表过短",
                "severity": "高"
            }
            recommendations.append("在确定诊断前，主动寻找反驳当前诊断的证据，问自己'还有什么其他可能？'")
        else:
            bias_analysis["过早闭合偏差"] = {"detected": False, "evidence": "诊断思路较为开放", "severity": "低"}
    else:
        bias_analysis["过早闭合偏差"] = {"detected": False, "evidence": "信息不足以评估", "severity": "未知"}

    # 检查可用性偏差 (Availability Bias)
    # 通过检查病史中是否提到"最近见过类似病例"等关键词
    availability_keywords = ["最近", "上次", "类似", "之前见过", "similar", "recent", "last patient", "just saw"]
    history_lower = history.lower()
    if any(kw in history_lower for kw in availability_keywords):
        cognitive_biases_detected.append("可用性偏差 (Availability Bias)")
        bias_analysis["可用性偏差"] = {
            "detected": True,
            "evidence": "病史描述中包含与近期病例比较的内容，可能受近期经验影响",
            "severity": "中"
        }
        recommendations.append("明确列出本病例与近期类似病例的不同之处，避免基于表面相似性做出诊断")
    else:
        bias_analysis["可用性偏差"] = {"detected": False, "evidence": "未发现明显可用性偏差迹象", "severity": "低"}

    # 检查确认偏差 (Confirmation Bias)
    # 如果体格检查发现与初步诊断高度一致，但鉴别诊断中没有相反的可能性
    if exam_findings and initial_diagnosis and diff_count > 0:
        # 简单检查：如果所有鉴别诊断都与初步诊断属于同一系统
        # 这里用简化逻辑：如果鉴别诊断数量少于2且体格检查内容较短
        if diff_count < 2 and len(exam_findings) < 50:
            cognitive_biases_detected.append("确认偏差 (Confirmation Bias)")
            bias_analysis["确认偏差"] = {
                "detected": True,
                "evidence": "体格检查记录简短且鉴别诊断有限，可能只记录了支持初步诊断的发现",
                "severity": "中"
            }
            recommendations.append("主动寻找与当前诊断不符的体征，记录所有阳性和阴性发现")
        else:
            bias_analysis["确认偏差"] = {"detected": False, "evidence": "体格检查记录较为全面", "severity": "低"}
    else:
        bias_analysis["确认偏差"] = {"detected": False, "evidence": "信息不足以评估", "severity": "未知"}

    # 如果没有检测到偏差，添加正面反馈
    if not cognitive_biases_detected:
        recommendations.append("诊断推理过程较为规范，继续保持系统性思维")
        recommendations.append("定期进行病例回顾，持续改进临床推理能力")
    else:
        recommendations.append("建议使用诊断核查清单，系统性地评估每个鉴别诊断")
        recommendations.append("在做出最终诊断前，询问自己：'如果我的初步诊断是错的，最可能的替代诊断是什么？'")

    return {
        "cognitive_biases_detected": cognitive_biases_detected,
        "bias_analysis": bias_analysis,
        "recommendations": recommendations,
        "differential_completeness_score": round(differential_completeness_score, 2)
    }

def search_clinical_guidelines(query, sources=None, limit=10):
    """
    使用 ToolUniverse API 搜索临床指南（支持 NICE、WHO、ADA、AHA/ACC、NCCN、SIGN、CPIC 等 12+ 权威来源）。

    参数：
    - query: 临床问题或疾病名称（英文，如 "diabetes management"）
    - sources: 指定数据源列表（可选），如 ["NICE", "WHO", "ADA"]，默认搜索所有来源
    - limit: 每个数据源返回的最大结果数（默认 10）

    返回：
    - guidelines: 指南列表，每个包含 {title, url, source, summary, date}
    - sources_searched: 实际搜索的数据源列表
    - total_results: 总结果数
    - query_used: 实际使用的查询字符串
    """
    import os
    import requests

    # 检查环境变量
    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {
            "error": "未设置 TOOLUNIVERSE_API_KEY 环境变量",
            "guidelines": [],
            "sources_searched": [],
            "total_results": 0
        }

    # 定义可用的数据源和对应的工具名称
    available_sources = {
        "NICE": "NICE_Clinical_Guidelines_Search",
        "WHO": "WHO_Guidelines_Search",
        "GIN": "GIN_Guidelines_Search",
        "SIGN": "SIGN_search_guidelines",
        "TRIP": "TRIP_Database_Guidelines_Search",
        "ADA": "ADA_search_standards",
        "AHA": "AHA_ACC_search_guidelines",
        "NCCN": "NCCN_search_guidelines",
        "CPIC": "CPIC_list_guidelines",
        "CMA": "CMA_Guidelines_Search",
        "OpenAlex": "OpenAlex_Guidelines_Search",
        "PubMed": "PubMed_Guidelines_Search"
    }

    # 确定要搜索的数据源
    if sources is None:
        sources_to_search = list(available_sources.keys())
    else:
        sources_to_search = [s for s in sources if s in available_sources]
        if not sources_to_search:
            return {
                "error": f"无效的数据源，可用数据源：{list(available_sources.keys())}",
                "guidelines": [],
                "sources_searched": [],
                "total_results": 0
            }

    # ToolUniverse API 基础 URL（实际 URL 需要根据 API 文档调整）
    base_url = "https://api.tooluniverse.ai/v1/tools/execute"

    guidelines = []
    sources_searched = []

    # 遍历每个数据源进行搜索
    for source in sources_to_search:
        tool_name = available_sources[source]

        try:
            # 构造 API 请求
            payload = {
                "tool_name": tool_name,
                "parameters": {
                    "query": query,
                    "limit": limit
                }
            }

            # 特殊处理：TRIP 需要 search_type 参数
            if source == "TRIP":
                payload["parameters"]["search_type"] = "guidelines"

            # 特殊处理：CPIC 不需要 query 参数（列出所有指南）
            if source == "CPIC":
                payload["parameters"] = {"limit": limit}

            headers = {
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json"
            }

            # 发起 API 请求（生产环境）
            # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
            # response.raise_for_status()
            # data = response.json()

            # Mock 实现（用于测试，实际部署时删除此部分）
            data = _mock_guideline_response(source, query, limit)

            # 解析结果
            if isinstance(data, dict) and "data" in data:
                results = data["data"] if isinstance(data["data"], list) else [data["data"]]
            elif isinstance(data, list):
                results = data
            else:
                results = []

            # 标准化结果格式
            for item in results:
                guideline = {
                    "title": item.get("title") or item.get("name") or "无标题",
                    "url": item.get("url") or "",
                    "source": source,
                    "summary": item.get("summary") or item.get("description") or item.get("content", "")[:200],
                    "date": item.get("date") or item.get("published") or item.get("year") or ""
                }
                guidelines.append(guideline)

            sources_searched.append(source)

        except Exception as e:
            # 单个数据源失败不影响其他数据源
            print(f"警告：搜索 {source} 时出错：{e}")
            continue

    return {
        "guidelines": guidelines,
        "sources_searched": sources_searched,
        "total_results": len(guidelines),
        "query_used": query
    }


