    - drug_name: 药物名称（英文，如 "metformin"、"aspirin"）
    - output_format: 输出格式（"markdown" 或 "dict"）

    返回：
    - report: 完整的药物研究报告（markdown 文本或结构化 dict）
    - sections: 报告包含的章节列表
    - data_sources: 使用的数据源列表
    - completeness_score: 数据完整性评分（0-100）
    """
    import os
    import requests
    from datetime import datetime

    # 检查环境变量
    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {
            "error": "未设置 TOOLUNIVERSE_API_KEY 环境变量",
            "report": "",
            "sections": [],
            "data_sources": [],
            "completeness_score": 0
        }

    # 报告章节定义
    sections = [
        "Executive Summary",
        "1. Compound Identity",
        "2. Chemical Properties",
        "3. Mechanism & Targets",
        "4. ADMET Properties",
        "5. Clinical Development",
        "6. Safety Profile",
        "7. Pharmacogenomics",
        "8. Regulatory Status",
        "9. Literature Evidence",
        "10. Clinical Recommendations",
        "11. Data Sources"
    ]

    # ToolUniverse API 基础 URL
    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }

    data_sources = []
    report_data = {}

    try:
        # 阶段 1：化合物消歧（Compound Disambiguation）
        # 使用 PubChem 获取化合物标识符
        payload = {
            "tool_name": "PubChem_get_compound_by_name",
            "parameters": {"name": drug_name}
        }
        # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
        # compound_data = response.json()

        # Mock 实现
        compound_data = _mock_compound_identity(drug_name)
        data_sources.append("PubChem")

        cid = compound_data.get("cid", "Unknown")
        smiles = compound_data.get("smiles", "Unknown")
        molecular_formula = compound_data.get("molecular_formula", "Unknown")

        # 阶段 2：化学性质
        # 使用 PubChem 获取化学性质
        report_data["chemical_properties"] = _mock_chemical_properties(drug_name)
        data_sources.append("ChEMBL")

        # 阶段 3：药理机制和靶点
