        report_data["mechanism"] = _mock_mechanism_targets(drug_name)
        data_sources.extend(["ChEMBL", "DGIdb"])

        # 阶段 4：ADMET 性质
        # 使用 ADMET-AI 工具
        report_data["admet"] = _mock_admet_properties(drug_name)
        data_sources.append("ADMET-AI")

        # 阶段 5：临床试验
        # 使用 ClinicalTrials.gov
        report_data["clinical_trials"] = _mock_clinical_trials(drug_name)
        data_sources.append("ClinicalTrials.gov")

        # 阶段 6：安全性
        # 使用 FAERS 和 DailyMed
        report_data["safety"] = _mock_safety_profile(drug_name)
        data_sources.extend(["FDA FAERS", "DailyMed"])

        # 阶段 7：药物基因组学
        # 使用 PharmGKB
        report_data["pharmacogenomics"] = _mock_pharmacogenomics(drug_name)
        data_sources.append("PharmGKB")

        # 阶段 8：监管状态
        report_data["regulatory"] = _mock_regulatory_status(drug_name)
        data_sources.append("FDA Orange Book")

        # 计算完整性评分
        completeness_score = _calculate_completeness(report_data)

        # 生成报告
        if output_format == "markdown":
            report = _generate_markdown_report(drug_name, cid, smiles, molecular_formula, report_data, data_sources)
        else:
            report = {
                "drug_name": drug_name,
                "cid": cid,
                "smiles": smiles,
                "molecular_formula": molecular_formula,
                **report_data
            }

        return {
            "report": report,
            "sections": sections,
            "data_sources": list(set(data_sources)),
            "completeness_score": completeness_score
        }

    except Exception as e:
        return {
            "error": f"生成报告时出错：{str(e)}",
            "report": "",
            "sections": sections,
            "data_sources": data_sources,
            "completeness_score": 0
        }


