    参数：
    - disease_name: 疾病名称（英文，如 "rheumatoid arthritis"、"alzheimer disease"）
    - strategy: 再利用策略（"disease-driven"、"target-based"、"compound-based"）
    - limit: 返回的候选药物数量上限（默认 10）

    返回：
    - candidates: 候选药物列表，每个包含 {drug_name, target, score, evidence, safety}
    - strategy_used: 使用的策略
    - disease_targets: 疾病相关靶点列表
    - total_candidates: 总候选药物数
    """
    import os
    import requests

    # 检查环境变量
    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {
            "error": "未设置 TOOLUNIVERSE_API_KEY 环境变量",
            "candidates": [],
            "strategy_used": strategy,
            "disease_targets": [],
            "total_candidates": 0
        }

    # ToolUniverse API 基础 URL
    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }

    candidates = []
    disease_targets = []

    try:
        # 阶段 1：获取疾病信息和相关靶点
        # 使用 OpenTargets 获取疾病 ID
        payload = {
            "tool_name": "OpenTargets_get_disease_id_description_by_name",
            "parameters": {"diseaseName": disease_name}
        }
        # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
        # disease_data = response.json()

        # Mock 实现
        disease_data = _mock_disease_info(disease_name)
        disease_id = disease_data.get("id", "Unknown")

        # 获取疾病相关靶点
        payload = {
            "tool_name": "OpenTargets_get_associated_targets_by_disease_efoId",
            "parameters": {"efoId": disease_id, "limit": 20}
        }
        # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
        # targets_data = response.json()

        # Mock 实现
        targets_data = _mock_disease_targets(disease_name)
        disease_targets = targets_data.get("targets", [])

        # 阶段 2：根据策略查找候选药物
        if strategy == "disease-driven":
            # 疾病驱动：疾病 → 靶点 → 药物
            for target in disease_targets[:10]:
                # 使用 DGIdb 查找靶向该靶点的药物
                payload = {
                    "tool_name": "DGIdb_get_drug_gene_interactions",
                    "parameters": {"gene_name": target["gene_symbol"]}
                }
                # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
                # drugs_data = response.json()

                # Mock 实现
                drugs_data = _mock_target_drugs(target["gene_symbol"])

                for drug in drugs_data.get("drugs", [])[:3]:
                    candidate = {
                        "drug_name": drug["name"],
                        "target": target["gene_symbol"],
                        "target_association_score": target.get("score", 0.5),
                        "interaction_type": drug.get("interaction_type", "unknown"),
                        "approval_status": drug.get("approval_status", "unknown"),
                        "evidence_count": 0,
                        "safety_profile": "unknown"
                    }
                    candidates.append(candidate)

        elif strategy == "target-based":
            # 靶点驱动：靶点 → 药物 → 新适应症
            # 类似逻辑，但从已知靶点开始
            pass

        elif strategy == "compound-based":
            # 化合物驱动：已批准药物 → 新靶点 → 新适应症
            # 类似逻辑，但从已批准药物开始
            pass

        # 阶段 3：评估安全性和文献证据
        for candidate in candidates:
            # 获取安全性数据（FDA 警告）
            payload = {
                "tool_name": "FDA_get_warnings_and_cautions_by_drug_name",
                "parameters": {"drug_name": candidate["drug_name"]}
            }
            # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
            # safety_data = response.json()

            # Mock 实现
            safety_data = _mock_safety_data(candidate["drug_name"])
            candidate["safety_profile"] = safety_data.get("profile", "unknown")
            candidate["black_box_warning"] = safety_data.get("black_box", False)

            # 搜索文献证据
            payload = {
                "tool_name": "PubMed_search_articles",
                "parameters": {
                    "query": f"{candidate['drug_name']} AND {disease_name}",
                    "max_results": 50
                }
            }
            # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
            # literature_data = response.json()

            # Mock 实现
            literature_data = _mock_literature_evidence(candidate["drug_name"], disease_name)
            candidate["evidence_count"] = literature_data.get("count", 0)

        # 阶段 4：评分和排序
        for candidate in candidates:
            candidate["repurposing_score"] = _calculate_repurposing_score(candidate)

        # 按评分排序
        candidates = sorted(candidates, key=lambda x: x["repurposing_score"], reverse=True)

        # 限制返回数量
        candidates = candidates[:limit]

        return {
            "candidates": candidates,
            "strategy_used": strategy,
            "disease_targets": [t["gene_symbol"] for t in disease_targets[:10]],
            "total_candidates": len(candidates)
        }

    except Exception as e:
        return {
            "error": f"分析药物再利用时出错：{str(e)}",
            "candidates": [],
            "strategy_used": strategy,
            "disease_targets": [],
            "total_candidates": 0
        }


