def _calculate_repurposing_score(candidate):
    """计算药物再利用评分（0-100）"""
    score = 0

    # 靶点关联强度（0-40 分）
    score += candidate.get("target_association_score", 0) * 40

    # 批准状态（0-20 分）
    if candidate.get("approval_status") == "approved":
        score += 20
    elif candidate.get("approval_status") == "clinical":
        score += 10

    # 安全性（0-20 分）
    if not candidate.get("black_box_warning", False):
        score += 10
    if candidate.get("safety_profile") == "良好":
        score += 10

    # 文献证据（0-20 分）
    evidence_count = candidate.get("evidence_count", 0)
    score += min(evidence_count / 5 * 20, 20)

    return round(score, 2)

def analyze_drug_drug_interaction(drug_list, analysis_type="pairwise"):
    """
    分析药物相互作用（DDI），包括机制识别、严重程度分类和临床管理建议。

    参数：
    - drug_list: 药物名称列表（英文），如 ["warfarin", "aspirin"] 或 ["drug1", "drug2", "drug3"]
    - analysis_type: 分析类型（"pairwise" 两两分析，"polypharmacy" 多药联用分析）

    返回：
    - interactions: 相互作用列表，每个包含 {drug_pair, severity, mechanism, risk_score, recommendation}
    - overall_risk_score: 总体风险评分（0-100）
    - high_risk_pairs: 高风险药物对列表
    - management_summary: 临床管理建议摘要
    """
    import os
    import requests

    # 检查环境变量
    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {
            "error": "未设置 TOOLUNIVERSE_API_KEY 环境变量",
            "interactions": [],
            "overall_risk_score": 0,
            "high_risk_pairs": [],
            "management_summary": ""
        }

    # 验证输入
    if len(drug_list) < 2:
        return {
            "error": "至少需要 2 个药物进行相互作用分析",
            "interactions": [],
            "overall_risk_score": 0,
            "high_risk_pairs": [],
            "management_summary": ""
        }

    # ToolUniverse API 基础 URL
    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }

    interactions = []
    high_risk_pairs = []

    try:
        # 生成药物对
        drug_pairs = []
        if analysis_type == "pairwise" or len(drug_list) == 2:
            # 两两分析
            for i in range(len(drug_list)):
                for j in range(i + 1, len(drug_list)):
                    drug_pairs.append((drug_list[i], drug_list[j]))
        else:
            # 多药联用分析（所有可能的两两组合）
            for i in range(len(drug_list)):
                for j in range(i + 1, len(drug_list)):
                    drug_pairs.append((drug_list[i], drug_list[j]))

        # 分析每个药物对
        for drug_a, drug_b in drug_pairs:
            # 阶段 1：使用 DrugBank 查询相互作用
            payload = {
                "tool_name": "drugbank_get_drug_interactions_by_drug_name_or_id",
                "parameters": {"drug_name_or_id": drug_a}
            }
            # response = requests.post(base_url, json=payload, headers=headers, timeout=30)
            # interaction_data = response.json()

            # Mock 实现
            interaction_data = _mock_drug_interaction(drug_a, drug_b)

            # 阶段 2：分析相互作用机制
            mechanism = _identify_interaction_mechanism(drug_a, drug_b, interaction_data)

            # 阶段 3：评估严重程度
            severity = _classify_severity(interaction_data)

            # 阶段 4：计算风险评分
            risk_score = _calculate_ddi_risk_score(interaction_data, mechanism, severity)

            # 阶段 5：生成临床建议
            recommendation = _generate_clinical_recommendation(drug_a, drug_b, severity, mechanism)

            # 构建相互作用记录
            interaction = {
                "drug_pair": f"{drug_a} + {drug_b}",
                "drug_a": drug_a,
                "drug_b": drug_b,
                "severity": severity,
                "mechanism": mechanism,
                "risk_score": risk_score,
                "description": interaction_data.get("description", "无详细描述"),
                "evidence_grade": interaction_data.get("evidence_grade", "★☆☆"),
                "recommendation": recommendation,
                "monitoring": interaction_data.get("monitoring", "常规监测"),
                "alternatives": interaction_data.get("alternatives", [])
            }

            interactions.append(interaction)

            # 标记高风险药物对
            if severity in ["Major", "Severe"] or risk_score >= 70:
                high_risk_pairs.append(f"{drug_a} + {drug_b}")

        # 计算总体风险评分
        if interactions:
            overall_risk_score = max([i["risk_score"] for i in interactions])
        else:
            overall_risk_score = 0

        # 生成管理建议摘要
        management_summary = _generate_management_summary(interactions, high_risk_pairs)

        return {
            "interactions": interactions,
            "overall_risk_score": overall_risk_score,
            "high_risk_pairs": high_risk_pairs,
            "management_summary": management_summary,
            "total_pairs_analyzed": len(drug_pairs)
        }

    except Exception as e:
        return {
            "error": f"分析药物相互作用时出错：{str(e)}",
            "interactions": [],
            "overall_risk_score": 0,
            "high_risk_pairs": [],
            "management_summary": ""
        }


