def _identify_interaction_mechanism(drug_a, drug_b, interaction_data):
    """识别相互作用机制"""
    mechanism = interaction_data.get("mechanism", "")
    if "CYP" in mechanism:
        return "CYP450 酶抑制/诱导"
    elif "药效学" in mechanism or "协同" in mechanism:
        return "药效学相互作用"
    elif "肾" in mechanism:
        return "肾脏排泄竞争"
    elif "转运体" in mechanism:
        return "药物转运体相互作用"
    else:
        return "未知机制"


def _classify_severity(interaction_data):
    """分类严重程度"""
    severity = interaction_data.get("severity", "Minor")
    # 标准化严重程度分类
    severity_map = {
        "Major": "Major",
        "Severe": "Major",
        "Moderate": "Moderate",
        "Minor": "Minor",
        "Contraindicated": "Contraindicated"
    }
    return severity_map.get(severity, "Minor")


def _calculate_ddi_risk_score(interaction_data, mechanism, severity):
    """计算 DDI 风险评分（0-100）"""
    score = 0

    # 严重程度（0-50 分）
    severity_scores = {
        "Contraindicated": 50,
        "Major": 40,
        "Moderate": 25,
        "Minor": 10
    }
    score += severity_scores.get(severity, 10)

    # 证据等级（0-30 分）
    evidence_grade = interaction_data.get("evidence_grade", "★☆☆")
    if evidence_grade == "★★★":
        score += 30
    elif evidence_grade == "★★☆":
        score += 20
    else:
        score += 10

    # 机制明确性（0-20 分）
    if mechanism != "未知机制":
        score += 20

    return min(score, 100)


def _generate_clinical_recommendation(drug_a, drug_b, severity, mechanism):
    """生成临床建议"""
    if severity == "Contraindicated":
        return f"禁忌联用 {drug_a} 和 {drug_b}，建议更换其中一种药物"
    elif severity == "Major":
        return f"避免联用 {drug_a} 和 {drug_b}，如必须联用需密切监测"
    elif severity == "Moderate":
        return f"{drug_a} 和 {drug_b} 联用需谨慎，建议调整剂量或加强监测"
    else:
        return f"{drug_a} 和 {drug_b} 联用风险较低，常规监测即可"


def _generate_management_summary(interactions, high_risk_pairs):
    """生成管理建议摘要"""
    if not interactions:
        return "未发现显著药物相互作用"

    summary_parts = []

    if high_risk_pairs:
        summary_parts.append(f"发现 {len(high_risk_pairs)} 个高风险药物对：{', '.join(high_risk_pairs)}")
        summary_parts.append("建议：")
        for pair in high_risk_pairs:
            summary_parts.append(f"  - {pair}：避免联用或密切监测")
    else:
        summary_parts.append("未发现高风险药物相互作用")

    major_count = len([i for i in interactions if i["severity"] == "Major"])
    moderate_count = len([i for i in interactions if i["severity"] == "Moderate"])

    if major_count > 0:
        summary_parts.append(f"严重相互作用：{major_count} 个")
    if moderate_count > 0:
        summary_parts.append(f"中度相互作用：{moderate_count} 个")

    return "\n".join(summary_parts)

def diagnose_rare_disease(phenotypes, genetic_data=None, limit=10):
    """
    基于表型和遗传数据进行罕见病鉴别诊断。
    将症状映射到 HPO 术语，从 Orphanet/OMIM 识别候选疾病，
    优先推荐基因检测，解读意义不明变异（VUS）。

    参数：
    - phenotypes: 患者表型列表（英文），如 ['tall stature', 'arachnodactyly']
    - genetic_data: 遗传数据（可选），含 variants 和 genes 字段
    - limit: 返回的候选疾病数量上限，默认 10

    返回：
    - candidate_diseases: 候选疾病列表，每项含 disease_name, omim_id, match_score, genes
    - hpo_terms: 匹配到的 HPO 术语列表
    - recommended_genes: 推荐检测的基因列表
    - differential_diagnosis: 鉴别诊断摘要
    """
    import os, requests

    if not phenotypes or not isinstance(phenotypes, list):
        return {"error": "phenotypes 必须是非空列表", "candidate_diseases": [],
                "hpo_terms": [], "recommended_genes": [], "differential_diagnosis": ""}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量",
                "candidate_diseases": [], "hpo_terms": [],
                "recommended_genes": [], "differential_diagnosis": ""}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
    hpo_terms, candidate_diseases = [], []

    try:
        # 阶段 1：将症状转换为 HPO 术语
        for symptom in phenotypes:
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "HPO_search_terms", "parameters": {"query": symptom}})
            if resp.status_code == 200:
                results = resp.json().get("data", {}).get("results", [])
                if results:
                    hpo_terms.append({"original": symptom,
                                      "hpo_id": results[0].get("id", ""),
                                      "hpo_name": results[0].get("name", symptom)})

        # 阶段 2：通过 Orphanet 搜索候选疾病
        for symptom in phenotypes[:5]:
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "Orphanet_search_diseases",
                "parameters": {"operation": "search_diseases", "query": symptom}})
            if resp.status_code == 200:
                for d in resp.json().get("data", {}).get("results", [])[:3]:
                    orpha_code = d.get("ORPHAcode")
                    entry = {"disease_name": d.get("name", ""), "orpha_code": orpha_code,
                             "omim_id": d.get("omim_id", ""), "match_score": 0.0, "genes": []}
                    if orpha_code:
                        gr = requests.post(base_url, headers=headers, timeout=30, json={
                            "tool_name": "Orphanet_get_genes",
                            "parameters": {"operation": "get_genes", "orpha_code": orpha_code}})
                        if gr.status_code == 200:
                            entry["genes"] = [g.get("symbol", "") for g in
                                              gr.json().get("data", {}).get("genes", [])]
                    candidate_diseases.append(entry)

        # 阶段 3：计算匹配分数，去重排序
        total_hpo = max(len(hpo_terms), 1)
        for d in candidate_diseases:
            d["match_score"] = round(min(len(d["genes"]) / total_hpo, 1.0), 2)
        seen, unique = set(), []
        for d in candidate_diseases:
            if d["disease_name"] not in seen:
                seen.add(d["disease_name"]); unique.append(d)
        candidate_diseases = sorted(unique, key=lambda x: x["match_score"], reverse=True)[:limit]

        # 阶段 4：汇总推荐基因
        gene_set = set()
        for d in candidate_diseases:
            gene_set.update(d["genes"])
        recommended_genes = list(gene_set)[:20]

        # 阶段 5：解读遗传变异（如有）
        variant_notes = []
        if genetic_data and isinstance(genetic_data, dict):
            for variant in genetic_data.get("variants", [])[:5]:
                resp = requests.post(base_url, headers=headers, timeout=30, json={
                    "tool_name": "ClinVar_search_variants", "parameters": {"query": variant}})
                if resp.status_code == 200:
                    sig = resp.json().get("data", {}).get("clinical_significance", "未知")
                    variant_notes.append(f"{variant}: {sig}")

        top_names = [d["disease_name"] for d in candidate_diseases[:3]]
        summary = f"基于 {len(phenotypes)} 个表型，识别到 {len(candidate_diseases)} 个候选疾病。"
        if top_names:
            summary += f" 优先考虑：{', '.join(top_names)}。"
        if variant_notes:
            summary += f" 变异解读：{'; '.join(variant_notes)}。"

        return {"candidate_diseases": candidate_diseases, "hpo_terms": hpo_terms,
                "recommended_genes": recommended_genes, "differential_diagnosis": summary}

    except Exception as e:
        return {"error": f"罕见病诊断分析时出错：{str(e)}", "candidate_diseases": [],
                "hpo_terms": [], "recommended_genes": [], "differential_diagnosis": ""}

def analyze_drug_safety_signals(drug_name, analysis_type="comprehensive", time_period="2020-2025"):
    """
    从 FDA FAERS 不良事件报告、药品标签警告和药物基因组数据分析药物安全信号。
    计算不成比例性指标（PRR、ROR），识别严重不良事件，评估药物基因组风险变异。

    参数：
    - drug_name: 药物名称（英文通用名），如 'metformin'、'warfarin'
    - analysis_type: 分析类型，'comprehensive'（全面）或 'faers_only'（仅 FAERS）
    - time_period: 数据时间段，如 '2020-2025'

    返回：
    - safety_signals: 安全信号列表，每项含 event, count, prr, severity, is_serious
    - boxed_warnings: FDA 黑框警告列表
    - pgx_variants: 药物基因组相关变异列表
    - risk_summary: 风险摘要
    - signal_count: 信号总数
    """
    import os, requests

    if not drug_name or not isinstance(drug_name, str):
        return {"error": "drug_name 必须是非空字符串", "safety_signals": [],
                "boxed_warnings": [], "pgx_variants": [], "risk_summary": "", "signal_count": 0}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量", "safety_signals": [],
                "boxed_warnings": [], "pgx_variants": [], "risk_summary": "", "signal_count": 0}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
    safety_signals, boxed_warnings, pgx_variants = [], [], []

    try:
        # 阶段 1：查询 FAERS 不良事件
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "FAERS_count_reactions_by_drug_event",
            "parameters": {"drug_name": drug_name, "limit": 50}})
        if resp.status_code == 200:
            for event in resp.json().get("data", {}).get("results", []):
                prr = event.get("prr", 1.0)
                safety_signals.append({
                    "event": event.get("reaction", ""),
                    "count": event.get("count", 0),
                    "prr": prr,
                    "severity": "high" if prr > 3.0 else ("medium" if prr > 2.0 else "low"),
                    "is_serious": event.get("serious", False)})

        # 阶段 2：获取 DailyMed 标签黑框警告
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "DailyMed_search_spls", "parameters": {"drug_name": drug_name}})
        if resp.status_code == 200:
            spls = resp.json().get("data", {}).get("results", [])
            if spls:
                setid = spls[0].get("setid", "")
                if setid:
                    lr = requests.post(base_url, headers=headers, timeout=30, json={
                        "tool_name": "DailyMed_get_spl_by_set_id", "parameters": {"setid": setid}})
                    if lr.status_code == 200:
                        bw = lr.json().get("data", {}).get("boxed_warning", "")
                        if bw:
                            boxed_warnings.append(bw)

        # 阶段 3：药物基因组数据（仅 comprehensive 模式）
        if analysis_type == "comprehensive":
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "PharmGKB_search_drug", "parameters": {"query": drug_name}})
            if resp.status_code == 200:
                for ann in resp.json().get("data", {}).get("clinical_annotations", [])[:10]:
                    pgx_variants.append({
                        "gene": ann.get("gene", ""), "variant": ann.get("variant", ""),
                        "phenotype": ann.get("phenotype", ""), "level": ann.get("level_of_evidence", "")})

        safety_signals.sort(key=lambda x: x["prr"], reverse=True)
        strong = [s for s in safety_signals if s["prr"] > 2.0]
        risk_summary = (f"药物 {drug_name} 共检测到 {len(safety_signals)} 个不良事件信号，"
                        f"其中强信号（PRR>2）{len(strong)} 个。")
        if boxed_warnings:
            risk_summary += f" 存在 {len(boxed_warnings)} 条黑框警告。"
        if pgx_variants:
            risk_summary += f" 发现 {len(pgx_variants)} 个药物基因组相关变异。"

        return {"safety_signals": safety_signals[:20], "boxed_warnings": boxed_warnings,
                "pgx_variants": pgx_variants, "risk_summary": risk_summary,
                "signal_count": len(safety_signals)}

    except Exception as e:
        return {"error": f"药物安全信号分析时出错：{str(e)}", "safety_signals": [],
                "boxed_warnings": [], "pgx_variants": [], "risk_summary": "", "signal_count": 0}

def detect_adverse_events(drug_name, event_type="all", statistical_method="prr"):
    """
    使用 FDA FAERS 数据、药品标签和生物医学证据检测和分析药物不良事件信号。
    生成量化安全信号评分（0-100），支持 PRR、ROR、IC 等不成比例性分析方法。

    参数：
    - drug_name: 药物名称（英文），如 'aspirin'、'ibuprofen'
    - event_type: 事件类型过滤，'all'、'serious'、'fatal' 或具体事件名
    - statistical_method: 统计方法，'prr'（比例报告比）、'ror'（报告比值比）、'ic'（信息成分）

    返回：
    - detected_signals: 检测到的信号列表，每项含 event, count, signal_score, method, is_serious
    - high_priority_signals: 高优先级信号（评分>50）
    - total_reports: 该药物总报告数
    - detection_summary: 检测摘要
    """
    import os, requests

    if not drug_name or not isinstance(drug_name, str):
        return {"error": "drug_name 必须是非空字符串", "detected_signals": [],
                "high_priority_signals": [], "total_reports": 0, "detection_summary": ""}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量", "detected_signals": [],
                "high_priority_signals": [], "total_reports": 0, "detection_summary": ""}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
    detected_signals = []

    try:
        # 阶段 1：从 FAERS 获取不良事件报告
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "FAERS_count_reactions_by_drug_event",
            "parameters": {"drug_name": drug_name, "limit": 100}})
        total_reports = 0
        if resp.status_code == 200:
            data = resp.json().get("data", {})
            total_reports = data.get("total_reports", 0)
            events = data.get("results", [])

            # 阶段 2：按事件类型过滤
            if event_type == "serious":
                events = [e for e in events if e.get("serious", False)]
            elif event_type == "fatal":
                events = [e for e in events if e.get("outcome") == "death"]
            elif event_type != "all":
                events = [e for e in events if event_type.lower() in e.get("reaction", "").lower()]

            # 阶段 3：计算信号评分
            for event in events:
                raw_stat = event.get(statistical_method, event.get("prr", 1.0))
                count = event.get("count", 0)
                # 信号评分 = min(统计量 * 10 + log10(count+1) * 10, 100)
                import math
                score = min(raw_stat * 10 + math.log10(count + 1) * 10, 100)
                detected_signals.append({
                    "event": event.get("reaction", ""),
                    "count": count,
                    "signal_score": round(score, 1),
                    "method": statistical_method,
                    "stat_value": raw_stat,
                    "is_serious": event.get("serious", False)})

        # 阶段 4：排序，提取高优先级信号
        detected_signals.sort(key=lambda x: x["signal_score"], reverse=True)
        high_priority = [s for s in detected_signals if s["signal_score"] > 50]

        summary = (f"药物 {drug_name} 共检测到 {len(detected_signals)} 个不良事件信号"
                   f"（方法：{statistical_method}），高优先级信号 {len(high_priority)} 个。")

        return {"detected_signals": detected_signals[:30], "high_priority_signals": high_priority[:10],
                "total_reports": total_reports, "detection_summary": summary}

    except Exception as e:
        return {"error": f"不良事件检测时出错：{str(e)}", "detected_signals": [],
                "high_priority_signals": [], "total_reports": 0, "detection_summary": ""}

def research_disease(disease_name, research_depth="standard"):
    """
    使用 100+ ToolUniverse 工具生成全面的疾病研究报告。
    涵盖疾病身份识别、临床表现、遗传基础、治疗方案、生物通路、流行病学等 10 个维度。

    参数：
    - disease_name: 疾病名称（英文），如 "Parkinson's disease"、"type 2 diabetes"
    - research_depth: 研究深度，'quick'（快速）或 'standard'（标准，默认）

    返回：
    - disease_identity: 疾病身份信息（EFO ID、ICD 编码、同义词）
    - associated_genes: 关联基因列表（含评分）
    - approved_drugs: 已批准药物列表
    - clinical_trials: 相关临床试验列表
    - key_pathways: 关键生物通路
    - research_summary: 研究摘要
    """
    import os, requests

    if not disease_name or not isinstance(disease_name, str):
        return {"error": "disease_name 必须是非空字符串", "disease_identity": {},
                "associated_genes": [], "approved_drugs": [], "clinical_trials": [],
                "key_pathways": [], "research_summary": ""}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量", "disease_identity": {},
                "associated_genes": [], "approved_drugs": [], "clinical_trials": [],
                "key_pathways": [], "research_summary": ""}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}

    try:
        # 维度 1：疾病身份识别（EFO ID）
        disease_identity = {}
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "OpenTargets_get_disease_id_description_by_name",
            "parameters": {"diseaseName": disease_name}})
        if resp.status_code == 200:
            d = resp.json().get("data", {})
            disease_identity = {"efo_id": d.get("id", ""), "name": d.get("name", disease_name),
                                "description": d.get("description", "")}

        efo_id = disease_identity.get("efo_id", "")

        # 维度 2：关联基因
        associated_genes = []
        if efo_id:
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "OpenTargets_get_associated_targets_by_disease_efoId",
                "parameters": {"efoId": efo_id, "limit": 20}})
            if resp.status_code == 200:
                for g in resp.json().get("data", {}).get("targets", []):
                    associated_genes.append({
                        "gene_symbol": g.get("symbol", ""), "score": g.get("score", 0),
                        "ensembl_id": g.get("id", "")})

        # 维度 3：已批准药物
        approved_drugs = []
        if efo_id:
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "OpenTargets_get_associated_drugs_by_disease_efoId",
                "parameters": {"efoId": efo_id, "size": 20}})
            if resp.status_code == 200:
                for drug in resp.json().get("data", {}).get("drugs", []):
                    approved_drugs.append({
                        "drug_name": drug.get("name", ""), "chembl_id": drug.get("id", ""),
                        "max_phase": drug.get("maximumClinicalTrialPhase", 0)})

        # 维度 4：临床试验
        clinical_trials = []
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "search_clinical_trials",
            "parameters": {"condition": disease_name, "pageSize": 10}})
        if resp.status_code == 200:
            for t in resp.json().get("data", {}).get("trials", []):
                clinical_trials.append({
                    "nct_id": t.get("nctId", ""), "title": t.get("briefTitle", ""),
                    "phase": t.get("phase", ""), "status": t.get("overallStatus", "")})

        # 维度 5：关键通路（仅 standard 模式）
        key_pathways = []
        if research_depth == "standard" and associated_genes:
            top_gene = associated_genes[0].get("ensembl_id", "")
            if top_gene:
                resp = requests.post(base_url, headers=headers, timeout=30, json={
                    "tool_name": "Reactome_map_uniprot_to_pathways",
                    "parameters": {"id": top_gene}})
                if resp.status_code == 200:
                    for p in resp.json().get("data", {}).get("pathways", [])[:10]:
                        key_pathways.append({
                            "pathway_name": p.get("name", ""), "pathway_id": p.get("stId", "")})

        research_summary = (
            f"疾病 '{disease_name}' 研究完成。"
            f" 关联基因 {len(associated_genes)} 个，已批准药物 {len(approved_drugs)} 种，"
            f" 临床试验 {len(clinical_trials)} 项，关键通路 {len(key_pathways)} 条。"
        )

        return {"disease_identity": disease_identity, "associated_genes": associated_genes,
                "approved_drugs": approved_drugs, "clinical_trials": clinical_trials,
                "key_pathways": key_pathways, "research_summary": research_summary}

    except Exception as e:
        return {"error": f"疾病研究时出错：{str(e)}", "disease_identity": {},
                "associated_genes": [], "approved_drugs": [], "clinical_trials": [],
                "key_pathways": [], "research_summary": ""}

def deep_literature_research(query, databases=None, max_results=50):
    """
    对生物医学目标进行全面文献研究，包含目标消歧、证据分级和结构化主题提取。
    支持多数据库检索（PubMed、Europe PMC、Semantic Scholar 等），生成带证据等级的研究报告。

    参数：
    - query: 研究查询词（英文），如 'EGFR lung cancer targeted therapy'
    - databases: 检索数据库列表，默认 ['pubmed', 'europepmc', 'semanticscholar']
    - max_results: 每个数据库最大返回结果数，默认 50

    返回：
    - papers: 文献列表，每项含 title, pmid, year, journal, citations
    - themes: 主题聚类列表，每项含 theme_name, paper_count, evidence_quality
    - target_profile: 目标蛋白/基因基本信息（如适用）
    - research_summary: 研究摘要
    - total_papers: 去重后总文献数
    """
    import os, requests

    if not query or not isinstance(query, str):
        return {"error": "query 必须是非空字符串", "papers": [], "themes": [],
                "target_profile": {}, "research_summary": "", "total_papers": 0}

    if databases is None:
        databases = ["pubmed", "europepmc", "semanticscholar"]

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量", "papers": [], "themes": [],
                "target_profile": {}, "research_summary": "", "total_papers": 0}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
    all_papers = []

    try:
        # 阶段 1：多数据库文献检索
        db_tool_map = {
            "pubmed": ("PubMed_search_articles", {"query": query, "limit": max_results}),
            "europepmc": ("EuropePMC_search_articles", {"query": query, "limit": max_results}),
            "semanticscholar": ("SemanticScholar_search_papers", {"query": query, "limit": max_results})
        }
        for db in databases:
            if db in db_tool_map:
                tool_name, params = db_tool_map[db]
                resp = requests.post(base_url, headers=headers, timeout=30, json={
                    "tool_name": tool_name, "parameters": params})
                if resp.status_code == 200:
                    results = resp.json().get("data", {}).get("results", [])
                    for r in results:
                        all_papers.append({
                            "title": r.get("title", ""), "pmid": r.get("pmid", r.get("paperId", "")),
                            "year": r.get("year", r.get("publicationDate", "")[:4] if r.get("publicationDate") else ""),
                            "journal": r.get("journal", r.get("venue", "")),
                            "citations": r.get("citationCount", 0), "source_db": db})

        # 阶段 2：去重（按标题）
        seen_titles, unique_papers = set(), []
        for p in all_papers:
            t = p["title"].lower()[:80]
            if t not in seen_titles:
                seen_titles.add(t); unique_papers.append(p)
        unique_papers.sort(key=lambda x: x["citations"], reverse=True)

        # 阶段 3：目标蛋白信息（如查询词像基因名）
        target_profile = {}
        query_words = query.split()
        if len(query_words) <= 3:  # 短查询可能是基因名
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "MyGene_query_genes",
                "parameters": {"q": query_words[0], "species": "human"}})
            if resp.status_code == 200:
                gene_data = resp.json().get("data", {})
                if gene_data.get("symbol"):
                    target_profile = {
                        "symbol": gene_data.get("symbol", ""),
                        "name": gene_data.get("name", ""),
                        "entrez_id": gene_data.get("entrezgene", ""),
                        "summary": gene_data.get("summary", "")[:200]}

        # 阶段 4：简单主题聚类（按关键词频率）
        from collections import Counter
        word_counts = Counter()
        for p in unique_papers[:50]:
            for word in p["title"].lower().split():
                if len(word) > 5:
                    word_counts[word] += 1
        themes = [{"theme_name": word, "paper_count": count,
                   "evidence_quality": "strong" if count > 5 else "moderate"}
                  for word, count in word_counts.most_common(10)]

        research_summary = (
            f"查询 '{query}' 共检索到 {len(unique_papers)} 篇去重文献"
            f"（来源：{', '.join(databases)}），识别到 {len(themes)} 个主题。"
        )
        if target_profile.get("symbol"):
            research_summary += f" 目标基因：{target_profile['symbol']}。"

        return {"papers": unique_papers[:max_results], "themes": themes,
                "target_profile": target_profile, "research_summary": research_summary,
                "total_papers": len(unique_papers)}

    except Exception as e:
        return {"error": f"文献深度研究时出错：{str(e)}", "papers": [], "themes": [],
                "target_profile": {}, "research_summary": "", "total_papers": 0}

def design_clinical_trial(indication, intervention, phase="Phase 2"):
    """
    使用 ToolUniverse 进行临床试验设计可行性评估。
    评估患者群体规模、生物标志物流行率、终点选择、对照药分析、安全监测和监管路径。

    参数：
    - indication: 适应症（英文），如 'EGFR-mutant non-small cell lung cancer'
    - intervention: 干预措施（英文），如 'osimertinib'、'CAR-T cell therapy'
    - phase: 试验阶段，'Phase 1'、'Phase 2'（默认）或 'Phase 3'

    返回：
    - feasibility_score: 可行性综合评分（0-100）
    - patient_population: 患者群体估算信息
    - endpoint_recommendations: 推荐终点列表
    - comparator_analysis: 对照药分析
    - regulatory_pathway: 监管路径建议
    - design_summary: 设计摘要
    """
    import os, requests

    if not indication or not intervention:
        return {"error": "indication 和 intervention 均为必填项", "feasibility_score": 0,
                "patient_population": {}, "endpoint_recommendations": [],
                "comparator_analysis": {}, "regulatory_pathway": "", "design_summary": ""}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量", "feasibility_score": 0,
                "patient_population": {}, "endpoint_recommendations": [],
                "comparator_analysis": {}, "regulatory_pathway": "", "design_summary": ""}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}

    try:
        # 维度 1：获取疾病信息和患者群体
        patient_population = {}
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "OpenTargets_get_disease_id_description_by_name",
            "parameters": {"diseaseName": indication}})
        if resp.status_code == 200:
            d = resp.json().get("data", {})
            patient_population = {
                "disease_name": d.get("name", indication),
                "efo_id": d.get("id", ""),
                "description": d.get("description", "")[:200]}

        # 维度 2：检索同类已完成试验（评估终点先例）
        existing_trials = []
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "search_clinical_trials",
            "parameters": {"condition": indication, "intervention": intervention,
                           "phase": phase, "pageSize": 20}})
        if resp.status_code == 200:
            existing_trials = resp.json().get("data", {}).get("trials", [])

        # 维度 3：干预药物信息（ChEMBL）
        comparator_analysis = {}
        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "ChEMBL_search_drugs", "parameters": {"query": intervention}})
        if resp.status_code == 200:
            drugs = resp.json().get("data", {}).get("results", [])
            if drugs:
                comparator_analysis = {
                    "intervention_chembl": drugs[0].get("molecule_chembl_id", ""),
                    "max_phase": drugs[0].get("max_phase", 0),
                    "mechanism": drugs[0].get("mechanism_of_action", "")}

        # 维度 4：推荐终点（基于已有试验）
        endpoint_recommendations = []
        if existing_trials:
            resp = requests.post(base_url, headers=headers, timeout=30, json={
                "tool_name": "get_clinical_trial_outcome_measures",
                "parameters": {"nct_ids": [t.get("nctId", "") for t in existing_trials[:5]]}})
            if resp.status_code == 200:
                outcomes = resp.json().get("data", {}).get("outcomes", [])
                from collections import Counter
                outcome_counts = Counter(o.get("measure", "") for o in outcomes)
                endpoint_recommendations = [
                    {"endpoint": ep, "precedent_count": cnt,
                     "evidence_grade": "A" if cnt >= 3 else ("B" if cnt >= 1 else "C")}
                    for ep, cnt in outcome_counts.most_common(5)
                ]

        # 维度 5：监管路径
        regulatory_pathway = (
            f"{phase} 试验，适应症：{indication}。"
            f" 建议参考 FDA 相关指南，考虑快速通道资格（若为严重疾病且满足未满足医疗需求）。"
        )

        # 计算可行性评分
        score = 0
        if patient_population.get("efo_id"):
            score += 30  # 疾病可识别
        if existing_trials:
            score += min(len(existing_trials) * 5, 25)  # 有先例试验
        if endpoint_recommendations:
            score += min(len(endpoint_recommendations) * 5, 25)  # 有推荐终点
        if comparator_analysis.get("max_phase", 0) >= 3:
            score += 20  # 干预药物已有 Phase 3 数据
        feasibility_score = min(score, 100)

        design_summary = (
            f"'{indication}' 的 {phase} 试验可行性评分：{feasibility_score}/100。"
            f" 找到 {len(existing_trials)} 个同类试验先例，推荐 {len(endpoint_recommendations)} 个终点。"
        )

        return {"feasibility_score": feasibility_score, "patient_population": patient_population,
                "endpoint_recommendations": endpoint_recommendations,
                "comparator_analysis": comparator_analysis,
                "regulatory_pathway": regulatory_pathway, "design_summary": design_summary}

    except Exception as e:
        return {"error": f"临床试验设计评估时出错：{str(e)}", "feasibility_score": 0,
                "patient_population": {}, "endpoint_recommendations": [],
                "comparator_analysis": {}, "regulatory_pathway": "", "design_summary": ""}

def match_clinical_trials(patient_profile, location="", limit=10):
    """
    基于患者分子特征和临床特征，从 ClinicalTrials.gov 发现并排序临床试验。
    多维度匹配（分子适配性、临床标准、药物-生物标志物对齐、证据强度、地理可行性），
    为每个试验生成量化试验匹配评分（0-100）。

    参数：
    - patient_profile: 患者信息字典，含 disease（疾病）、biomarkers（生物标志物列表）、
                       stage（分期）、prior_treatments（既往治疗）等字段
    - location: 地理位置过滤（可选），如 'Boston, MA'、'Beijing'
    - limit: 返回的最大试验数量，默认 10

    返回：
    - matched_trials: 匹配试验列表，每项含 nct_id, title, match_score, phase, status, location
    - top_recommendation: 最佳推荐试验
    - match_summary: 匹配摘要
    - total_found: 找到的试验总数
    """
    import os, requests

    if not patient_profile or not isinstance(patient_profile, dict):
        return {"error": "patient_profile 必须是包含 disease 字段的字典",
                "matched_trials": [], "top_recommendation": {}, "match_summary": "", "total_found": 0}

    disease = patient_profile.get("disease", "")
    if not disease:
        return {"error": "patient_profile 必须包含 disease 字段",
                "matched_trials": [], "top_recommendation": {}, "match_summary": "", "total_found": 0}

    api_key = os.getenv("TOOLUNIVERSE_API_KEY")
    if not api_key:
        return {"error": "未配置 TOOLUNIVERSE_API_KEY 环境变量",
                "matched_trials": [], "top_recommendation": {}, "match_summary": "", "total_found": 0}

    base_url = "https://api.tooluniverse.ai/v1/tools/execute"
    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}

    try:
        # 阶段 1：搜索相关临床试验
        search_params = {
            "condition": disease,
            "status": "RECRUITING",
            "pageSize": 50
        }
        if location:
            search_params["location"] = location

        resp = requests.post(base_url, headers=headers, timeout=30, json={
            "tool_name": "search_clinical_trials", "parameters": search_params})
        trials = []
        if resp.status_code == 200:
            trials = resp.json().get("data", {}).get("trials", [])

        # 阶段 2：获取生物标志物相关试验（如有）
        biomarkers = patient_profile.get("biomarkers", [])
        if biomarkers:
            for bm in biomarkers[:3]:
                resp = requests.post(base_url, headers=headers, timeout=30, json={
                    "tool_name": "search_clinical_trials",
                    "parameters": {"condition": disease, "intervention": bm,
                                   "status": "RECRUITING", "pageSize": 20}})
                if resp.status_code == 200:
                    bm_trials = resp.json().get("data", {}).get("trials", [])
                    trials.extend(bm_trials)

        # 阶段 3：去重
        seen_nct, unique_trials = set(), []
        for t in trials:
            nct = t.get("nctId", "")
            if nct and nct not in seen_nct:
                seen_nct.add(nct); unique_trials.append(t)

        # 阶段 4：计算匹配评分
        stage = patient_profile.get("stage", "")
        prior_treatments = patient_profile.get("prior_treatments", [])

        def calc_match_score(trial):
            score = 50  # 基础分（疾病匹配）
            title_lower = trial.get("briefTitle", "").lower()
            # 生物标志物匹配加分
            for bm in biomarkers:
                if bm.lower() in title_lower:
                    score += 15
                    break
            # 分期匹配加分
            if stage and stage.lower() in title_lower:
                score += 10
            # Phase 2/3 优先
            phase = trial.get("phase", "")
            if "3" in phase:
                score += 10
            elif "2" in phase:
                score += 5
            # 地理位置匹配
            if location and location.lower() in str(trial.get("locations", "")).lower():
                score += 10
            return min(score, 100)

        matched_trials = []
        for t in unique_trials:
            match_score = calc_match_score(t)
            matched_trials.append({
                "nct_id": t.get("nctId", ""),
                "title": t.get("briefTitle", ""),
                "match_score": match_score,
                "phase": t.get("phase", ""),
                "status": t.get("overallStatus", ""),
                "sponsor": t.get("leadSponsor", "")})

        matched_trials.sort(key=lambda x: x["match_score"], reverse=True)
        matched_trials = matched_trials[:limit]
        top_recommendation = matched_trials[0] if matched_trials else {}

        match_summary = (
            f"患者（{disease}）共找到 {len(unique_trials)} 个招募中试验，"
            f" 返回评分最高的 {len(matched_trials)} 个。"
        )
        if top_recommendation:
            match_summary += f" 最佳推荐：{top_recommendation['title']}（评分 {top_recommendation['match_score']}）。"

        return {"matched_trials": matched_trials, "top_recommendation": top_recommendation,
                "match_summary": match_summary, "total_found": len(unique_trials)}

    except Exception as e:
        return {"error": f"临床试验匹配时出错：{str(e)}", "matched_trials": [],
                "top_recommendation": {}, "match_summary": "", "total_found": 0}

def analyze_nutrition(nutrition_data, analysis_type="comprehensive", time_range=30):
    """
    分析营养数据，评估营养状况，提供个性化建议。

    参数：
    - nutrition_data: 营养数据字典，包含 daily_logs（每日记录列表）
      每条记录格式：{"date": "YYYY-MM-DD", "calories": 2000, "protein": 80, "carbs": 250, "fat": 70, ...}
    - analysis_type: 分析类型，可选 "trend"（趋势）、"assessment"（评估）、"comprehensive"（综合，默认）
    - time_range: 分析时间范围（天数），默认 30 天

    返回：
    - nutrition_score: 营养状况综合评分（0-100）
    - macronutrient_status: 宏量营养素状态（蛋白质、碳水、脂肪、纤维）
    - micronutrient_status: 微量营养素状态（维生素、矿物质）
    - deficiency_risks: 缺乏风险列表
    - recommendations: 个性化建议列表
    - trend_analysis: 趋势分析结果（如果 analysis_type 包含趋势）
    """

    # 参数验证
    if not nutrition_data or not isinstance(nutrition_data, dict):
        return {
            "error": "nutrition_data 必须是包含 daily_logs 的字典",
            "nutrition_score": 0,
            "macronutrient_status": {},
            "micronutrient_status": {},
            "deficiency_risks": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    daily_logs = nutrition_data.get("daily_logs", [])
    if not daily_logs or not isinstance(daily_logs, list):
        return {
            "error": "nutrition_data 必须包含非空的 daily_logs 列表",
            "nutrition_score": 0,
            "macronutrient_status": {},
            "micronutrient_status": {},
            "deficiency_risks": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    # 限制分析范围
    recent_logs = daily_logs[-time_range:] if len(daily_logs) > time_range else daily_logs

    if len(recent_logs) == 0:
        return {
            "error": "没有可分析的营养数据",
            "nutrition_score": 0,
            "macronutrient_status": {},
            "micronutrient_status": {},
            "deficiency_risks": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    # RDA 参考值（成年人，每日推荐摄入量）
    rda_standards = {
        "calories": {"min": 1800, "max": 2500, "unit": "kcal"},
        "protein": {"min": 50, "max": 150, "unit": "g"},
        "carbs": {"min": 225, "max": 325, "unit": "g"},
        "fat": {"min": 44, "max": 78, "unit": "g"},
        "fiber": {"min": 25, "max": 38, "unit": "g"},
        "vitamin_c": {"min": 75, "max": 2000, "unit": "mg"},
        "vitamin_d": {"min": 15, "max": 100, "unit": "mcg"},
        "calcium": {"min": 1000, "max": 2500, "unit": "mg"},
        "iron": {"min": 8, "max": 45, "unit": "mg"},
        "sodium": {"min": 1500, "max": 2300, "unit": "mg"}
    }

    # 计算平均摄入量
    avg_intake = {}
    for nutrient in rda_standards.keys():
        values = [log.get(nutrient, 0) for log in recent_logs if log.get(nutrient) is not None]
        avg_intake[nutrient] = sum(values) / len(values) if values else 0

    # 宏量营养素评估
    macronutrient_status = {}
    for nutrient in ["calories", "protein", "carbs", "fat", "fiber"]:
        intake = avg_intake.get(nutrient, 0)
        rda = rda_standards[nutrient]

        if intake < rda["min"] * 0.8:
            status = "不足"
            achievement = (intake / rda["min"]) * 100 if rda["min"] > 0 else 0
        elif intake < rda["min"]:
            status = "偏低"
            achievement = (intake / rda["min"]) * 100
        elif intake <= rda["max"]:
            status = "正常"
            achievement = 100
        elif intake <= rda["max"] * 1.2:
            status = "偏高"
            achievement = 100
        else:
            status = "过量"
            achievement = 100

        macronutrient_status[nutrient] = {
            "avg_intake": round(intake, 1),
            "rda_min": rda["min"],
            "rda_max": rda["max"],
            "unit": rda["unit"],
            "status": status,
            "achievement_rate": round(achievement, 1)
        }

    # 微量营养素评估
    micronutrient_status = {}
    for nutrient in ["vitamin_c", "vitamin_d", "calcium", "iron", "sodium"]:
        intake = avg_intake.get(nutrient, 0)
        rda = rda_standards[nutrient]

        if intake < rda["min"] * 0.7:
            status = "严重不足"
            achievement = (intake / rda["min"]) * 100 if rda["min"] > 0 else 0
        elif intake < rda["min"]:
            status = "不足"
            achievement = (intake / rda["min"]) * 100
        elif intake <= rda["max"]:
            status = "正常"
            achievement = 100
        else:
            status = "过量"
            achievement = 100

        micronutrient_status[nutrient] = {
            "avg_intake": round(intake, 1),
            "rda_min": rda["min"],
            "rda_max": rda["max"],
            "unit": rda["unit"],
            "status": status,
            "achievement_rate": round(achievement, 1)
        }

    # 识别缺乏风险
    deficiency_risks = []
    for nutrient, data in {**macronutrient_status, **micronutrient_status}.items():
        if data["status"] in ["严重不足", "不足", "偏低"]:
            risk_level = "高" if data["status"] == "严重不足" else ("中" if data["status"] == "不足" else "低")
            deficiency_risks.append({
                "nutrient": nutrient,
                "risk_level": risk_level,
                "current_intake": data["avg_intake"],
                "recommended_min": data["rda_min"],
                "unit": data["unit"]
            })

    # 生成个性化建议
    recommendations = []

    # 宏量营养素建议
    if macronutrient_status["protein"]["status"] in ["不足", "偏低"]:
        recommendations.append({
            "category": "宏量营养素",
            "priority": "高",
            "suggestion": f"增加蛋白质摄入至每日 {rda_standards['protein']['min']}g 以上，推荐食物：鸡胸肉、鱼类、豆制品、鸡蛋"
        })

    if macronutrient_status["fiber"]["status"] in ["不足", "偏低"]:
        recommendations.append({
            "category": "宏量营养素",
            "priority": "中",
            "suggestion": f"增加膳食纤维摄入至每日 {rda_standards['fiber']['min']}g 以上，推荐食物：全谷物、蔬菜、水果、豆类"
        })

    if macronutrient_status["calories"]["status"] == "过量":
        recommendations.append({
            "category": "能量管理",
            "priority": "高",
            "suggestion": f"控制每日热量摄入在 {rda_standards['calories']['max']} kcal 以内，减少高糖高脂食物"
        })

    # 微量营养素建议
    if micronutrient_status["vitamin_d"]["status"] in ["严重不足", "不足"]:
        recommendations.append({
            "category": "微量营养素",
            "priority": "高",
            "suggestion": f"增加维生素D摄入，推荐：多晒太阳（每日15-30分钟）、食用富含维生素D的食物（三文鱼、蛋黄、强化牛奶）或考虑补充剂"
        })

    if micronutrient_status["calcium"]["status"] in ["不足", "偏低"]:
        recommendations.append({
            "category": "微量营养素",
            "priority": "中",
            "suggestion": f"增加钙摄入至每日 {rda_standards['calcium']['min']}mg 以上，推荐食物：牛奶、酸奶、豆腐、绿叶蔬菜"
        })

    if micronutrient_status["sodium"]["status"] == "过量":
        recommendations.append({
            "category": "微量营养素",
            "priority": "高",
            "suggestion": f"减少钠摄入至每日 {rda_standards['sodium']['max']}mg 以内，避免高盐食物和加工食品"
        })

    # 趋势分析（如果请求）
    trend_analysis = {}
    if analysis_type in ["trend", "comprehensive"] and len(recent_logs) >= 7:
        # 计算最近7天和之前7天的平均值对比
        if len(recent_logs) >= 14:
            recent_7 = recent_logs[-7:]
            previous_7 = recent_logs[-14:-7]

            for nutrient in ["calories", "protein", "carbs", "fat", "fiber"]:
                recent_avg = sum(log.get(nutrient, 0) for log in recent_7) / 7
                previous_avg = sum(log.get(nutrient, 0) for log in previous_7) / 7

                if previous_avg > 0:
                    change_pct = ((recent_avg - previous_avg) / previous_avg) * 100
                    trend = "上升" if change_pct > 5 else ("下降" if change_pct < -5 else "稳定")
                else:
                    change_pct = 0
                    trend = "稳定"

                trend_analysis[nutrient] = {
                    "recent_avg": round(recent_avg, 1),
                    "previous_avg": round(previous_avg, 1),
                    "change_percent": round(change_pct, 1),
                    "trend": trend
                }

    # 计算综合营养评分
    score = 0
    total_nutrients = len(macronutrient_status) + len(micronutrient_status)

    for data in list(macronutrient_status.values()) + list(micronutrient_status.values()):
        if data["status"] == "正常":
            score += 10
        elif data["status"] in ["偏低", "偏高"]:
            score += 7
        elif data["status"] in ["不足", "过量"]:
            score += 4
        else:  # 严重不足
            score += 0

    nutrition_score = min(int((score / total_nutrients)), 100) if total_nutrients > 0 else 0

    return {
        "nutrition_score": nutrition_score,
        "macronutrient_status": macronutrient_status,
        "micronutrient_status": micronutrient_status,
        "deficiency_risks": deficiency_risks,
        "recommendations": recommendations,
        "trend_analysis": trend_analysis,
        "analysis_summary": f"分析了 {len(recent_logs)} 天的营养数据，综合评分 {nutrition_score}/100，发现 {len(deficiency_risks)} 项缺乏风险，生成 {len(recommendations)} 条建议。"
    }

def analyze_mental_health(mental_health_data, analysis_type="comprehensive"):
    """
    分析心理健康数据，评估心理状态，识别危机风险，提供个性化建议。

    参数：
    - mental_health_data: 心理健康数据字典，包含：
      - phq9_assessments: PHQ-9 抑郁评估列表 [{"date": "YYYY-MM-DD", "score": 0-27, "item9": 0-3}, ...]
      - gad7_assessments: GAD-7 焦虑评估列表 [{"date": "YYYY-MM-DD", "score": 0-21}, ...]
      - mood_logs: 情绪日志列表 [{"date": "YYYY-MM-DD", "mood": "happy/sad/anxious", "intensity": 1-10, "triggers": [...], "coping": [...]}, ...]
    - analysis_type: 分析类型，可选 "assessment"（评估）、"crisis"（危机）、"comprehensive"（综合，默认）

    返回：
    - mental_health_score: 心理健康综合评分（0-100，越高越好）
    - phq9_status: PHQ-9 抑郁状态
    - gad7_status: GAD-7 焦虑状态
    - crisis_risk: 危机风险评估
    - mood_patterns: 情绪模式分析
    - recommendations: 个性化建议列表
    """

    # 参数验证
    if not mental_health_data or not isinstance(mental_health_data, dict):
        return {
            "error": "mental_health_data 必须是包含评估数据的字典",
            "mental_health_score": 0,
            "phq9_status": {},
            "gad7_status": {},
            "crisis_risk": {},
            "mood_patterns": {},
            "recommendations": []
        }

    phq9_assessments = mental_health_data.get("phq9_assessments", [])
    gad7_assessments = mental_health_data.get("gad7_assessments", [])
    mood_logs = mental_health_data.get("mood_logs", [])

    if not phq9_assessments and not gad7_assessments and not mood_logs:
        return {
            "error": "至少需要提供 PHQ-9、GAD-7 或情绪日志数据之一",
            "mental_health_score": 0,
            "phq9_status": {},
            "gad7_status": {},
            "crisis_risk": {},
            "mood_patterns": {},
            "recommendations": []
        }

    # PHQ-9 抑郁评估分析
    phq9_status = {}
    if phq9_assessments:
        latest_phq9 = phq9_assessments[-1]
        score = latest_phq9.get("score", 0)
        item9 = latest_phq9.get("item9", 0)

        if score < 5:
            severity = "无抑郁"
        elif score < 10:
            severity = "轻度抑郁"
        elif score < 15:
            severity = "中度抑郁"
        elif score < 20:
            severity = "中重度抑郁"
        else:
            severity = "重度抑郁"

        # 计算趋势（如果有多次评估）
        trend = "稳定"
        change_rate = 0
        if len(phq9_assessments) >= 2:
            prev_score = phq9_assessments[-2].get("score", 0)
            change = score - prev_score
            change_rate = change

            if change <= -2:
                trend = "改善"
            elif change >= 2:
                trend = "恶化"

        phq9_status = {
            "current_score": score,
            "severity": severity,
            "item9_score": item9,
            "trend": trend,
            "change_rate": change_rate,
            "assessment_count": len(phq9_assessments)
        }

    # GAD-7 焦虑评估分析
    gad7_status = {}
    if gad7_assessments:
        latest_gad7 = gad7_assessments[-1]
        score = latest_gad7.get("score", 0)

        if score < 5:
            severity = "无焦虑"
        elif score < 10:
            severity = "轻度焦虑"
        elif score < 15:
            severity = "中度焦虑"
        else:
            severity = "重度焦虑"

        # 计算趋势
        trend = "稳定"
        change_rate = 0
        if len(gad7_assessments) >= 2:
            prev_score = gad7_assessments[-2].get("score", 0)
            change = score - prev_score
            change_rate = change

            if change <= -2:
                trend = "改善"
            elif change >= 2:
                trend = "恶化"

        gad7_status = {
            "current_score": score,
            "severity": severity,
            "trend": trend,
            "change_rate": change_rate,
            "assessment_count": len(gad7_assessments)
        }

    # 危机风险评估
    crisis_risk = {
        "risk_level": "低风险",
        "risk_score": 0,
        "risk_factors": [],
        "action_required": "继续监测，定期评估"
    }

    risk_score = 0

    # 风险因素1：PHQ-9 第9项（自伤意念）
    if phq9_status and phq9_status.get("item9_score", 0) >= 2:
        risk_score += 10
        crisis_risk["risk_factors"].append("PHQ-9第9项得分高（自伤意念频繁）")
    elif phq9_status and phq9_status.get("item9_score", 0) == 1:
        risk_score += 5
        crisis_risk["risk_factors"].append("PHQ-9第9项得分中等（偶有自伤意念）")

    # 风险因素2：症状快速恶化
    if phq9_status and phq9_status.get("change_rate", 0) >= 5:
        risk_score += 5
        crisis_risk["risk_factors"].append("抑郁症状快速恶化")
    elif phq9_status and phq9_status.get("change_rate", 0) >= 2:
        risk_score += 3
        crisis_risk["risk_factors"].append("抑郁症状恶化")

    if gad7_status and gad7_status.get("change_rate", 0) >= 5:
        risk_score += 3
        crisis_risk["risk_factors"].append("焦虑症状快速恶化")

    # 风险因素3：高强度负面情绪占比
    if mood_logs:
        negative_moods = ["sad", "anxious", "angry", "hopeless", "depressed"]
        high_intensity_negative = sum(
            1 for log in mood_logs[-30:]
            if log.get("mood") in negative_moods and log.get("intensity", 0) >= 7
        )
        negative_ratio = high_intensity_negative / min(len(mood_logs), 30)

        if negative_ratio > 0.7:
            risk_score += 3
            crisis_risk["risk_factors"].append("高强度负面情绪占比过高（>70%）")
        elif negative_ratio > 0.5:
            risk_score += 2
            crisis_risk["risk_factors"].append("高强度负面情绪占比较高（50-70%）")

    # 风险因素4：严重抑郁或焦虑
    if phq9_status and phq9_status.get("current_score", 0) >= 20:
        risk_score += 4
        crisis_risk["risk_factors"].append("重度抑郁症状")
    elif phq9_status and phq9_status.get("current_score", 0) >= 15:
        risk_score += 2
        crisis_risk["risk_factors"].append("中重度抑郁症状")

    if gad7_status and gad7_status.get("current_score", 0) >= 15:
        risk_score += 3
        crisis_risk["risk_factors"].append("重度焦虑症状")

    # 风险等级判定
    crisis_risk["risk_score"] = risk_score

    if risk_score >= 10:
        crisis_risk["risk_level"] = "高风险"
        crisis_risk["action_required"] = "立即就医（24小时内），启动危机干预。拨打心理危机热线：400-161-9995"
    elif risk_score >= 5:
        crisis_risk["risk_level"] = "中风险"
        crisis_risk["action_required"] = "密切关注，建议48小时内就医咨询专业心理医生"
    else:
        crisis_risk["risk_level"] = "低风险"
        crisis_risk["action_required"] = "继续监测，定期评估，保持健康生活方式"

    # 情绪模式分析
    mood_patterns = {}
    if mood_logs:
        # 统计最常见情绪
        from collections import Counter
        mood_counts = Counter(log.get("mood", "unknown") for log in mood_logs[-30:])
        top_moods = mood_counts.most_common(5)

        # 计算平均情绪强度
        avg_intensity = sum(log.get("intensity", 0) for log in mood_logs[-30:]) / min(len(mood_logs), 30)

        # 统计触发因素
        all_triggers = []
        for log in mood_logs[-30:]:
            all_triggers.extend(log.get("triggers", []))
        trigger_counts = Counter(all_triggers)
        top_triggers = trigger_counts.most_common(5)

        mood_patterns = {
            "top_moods": [{"mood": mood, "count": count} for mood, count in top_moods],
            "avg_intensity": round(avg_intensity, 1),
            "top_triggers": [{"trigger": trigger, "count": count} for trigger, count in top_triggers],
            "log_count": len(mood_logs)
        }

    # 生成个性化建议
    recommendations = []

    # 基于危机风险的建议
    if crisis_risk["risk_level"] == "高风险":
        recommendations.append({
            "category": "紧急行动",
            "priority": "最高",
            "suggestion": "立即联系心理医生或拨打心理危机热线（400-161-9995）。如有自伤或自杀想法，请立即前往急诊室。"
        })
    elif crisis_risk["risk_level"] == "中风险":
        recommendations.append({
            "category": "专业支持",
            "priority": "高",
            "suggestion": "建议48小时内预约心理咨询师或精神科医生，进行专业评估和治疗。"
        })

    # 基于 PHQ-9 的建议
    if phq9_status:
        if phq9_status.get("severity") in ["中度抑郁", "中重度抑郁", "重度抑郁"]:
            recommendations.append({
                "category": "抑郁症状管理",
                "priority": "高",
                "suggestion": "建议寻求专业心理治疗（如认知行为疗法CBT）。保持规律作息，适度运动，避免独处过久。"
            })
        elif phq9_status.get("severity") == "轻度抑郁":
            recommendations.append({
                "category": "抑郁症状管理",
                "priority": "中",
                "suggestion": "增加社交活动，保持规律运动（每周3-5次，每次30分钟），尝试正念冥想或放松训练。"
            })

    # 基于 GAD-7 的建议
    if gad7_status:
        if gad7_status.get("severity") in ["中度焦虑", "重度焦虑"]:
            recommendations.append({
                "category": "焦虑症状管理",
                "priority": "高",
                "suggestion": "学习焦虑管理技巧（深呼吸、渐进性肌肉放松）。减少咖啡因摄入，保证充足睡眠。考虑专业心理治疗。"
            })
        elif gad7_status.get("severity") == "轻度焦虑":
            recommendations.append({
                "category": "焦虑症状管理",
                "priority": "中",
                "suggestion": "练习深呼吸和正念冥想，减少压力源，保持规律作息。"
            })

    # 基于情绪模式的建议
    if mood_patterns and mood_patterns.get("avg_intensity", 0) >= 7:
        recommendations.append({
            "category": "情绪调节",
            "priority": "中",
            "suggestion": "情绪强度较高，建议学习情绪调节技巧（如情绪日记、认知重构）。识别并管理触发因素。"
        })

    # 通用建议
    if not recommendations or crisis_risk["risk_level"] == "低风险":
        recommendations.append({
            "category": "健康维护",
            "priority": "低",
            "suggestion": "保持健康生活方式：规律作息、适度运动、均衡饮食、充足睡眠、积极社交。定期进行心理健康自我评估。"
        })

    # 计算综合心理健康评分
    mental_health_score = 100

    if phq9_status:
        phq9_score = phq9_status.get("current_score", 0)
        mental_health_score -= min(phq9_score * 2, 50)

    if gad7_status:
        gad7_score = gad7_status.get("current_score", 0)
        mental_health_score -= min(gad7_score * 1.5, 30)

    mental_health_score -= min(risk_score * 2, 20)
    mental_health_score = max(0, int(mental_health_score))

    return {
        "mental_health_score": mental_health_score,
        "phq9_status": phq9_status,
        "gad7_status": gad7_status,
        "crisis_risk": crisis_risk,
        "mood_patterns": mood_patterns,
        "recommendations": recommendations,
        "analysis_summary": f"心理健康评分 {mental_health_score}/100，危机风险等级：{crisis_risk['risk_level']}，生成 {len(recommendations)} 条建议。"
    }

def analyze_sleep(sleep_data, analysis_type="comprehensive", time_range=30):
    """
    分析睡眠数据，评估睡眠质量，识别睡眠问题并提供个性化建议。

    参数：
    - sleep_data: 睡眠数据字典，包含 sleep_logs（每日睡眠记录列表）
      每条记录格式：{"date": "YYYY-MM-DD", "bedtime": "HH:MM", "wake_time": "HH:MM",
                     "sleep_duration": 7.5, "sleep_quality": "good/fair/poor",
                     "awakenings": 2, "sleep_latency": 15, ...}
    - analysis_type: 分析类型，可选 "trend"（趋势）、"quality"（质量）、"comprehensive"（综合，默认）
    - time_range: 分析时间范围（天数），默认 30 天

    返回：
    - sleep_score: 睡眠质量综合评分（0-100）
    - sleep_duration_status: 睡眠时长状态
    - sleep_quality_status: 睡眠质量状态
    - sleep_problems: 识别的睡眠问题列表
    - recommendations: 个性化建议列表
    - trend_analysis: 趋势分析结果（如果 analysis_type 包含趋势）
    """

    # 参数验证
    if not sleep_data or not isinstance(sleep_data, dict):
        return {
            "error": "sleep_data 必须是包含 sleep_logs 的字典",
            "sleep_score": 0,
            "sleep_duration_status": {},
            "sleep_quality_status": {},
            "sleep_problems": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    sleep_logs = sleep_data.get("sleep_logs", [])
    if not sleep_logs or not isinstance(sleep_logs, list):
        return {
            "error": "sleep_data 必须包含非空的 sleep_logs 列表",
            "sleep_score": 0,
            "sleep_duration_status": {},
            "sleep_quality_status": {},
            "sleep_problems": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    # 限制分析范围
    recent_logs = sleep_logs[-time_range:] if len(sleep_logs) > time_range else sleep_logs

    if len(recent_logs) == 0:
        return {
            "error": "没有可分析的睡眠数据",
            "sleep_score": 0,
            "sleep_duration_status": {},
            "sleep_quality_status": {},
            "sleep_problems": [],
            "recommendations": [],
            "trend_analysis": {}
        }

    # 睡眠时长分析
    durations = [log.get("sleep_duration", 0) for log in recent_logs if log.get("sleep_duration")]
    avg_duration = sum(durations) / len(durations) if durations else 0

    # 推荐睡眠时长：7-9小时
    if avg_duration < 6:
        duration_status = "严重不足"
        duration_score = 40
    elif avg_duration < 7:
        duration_status = "不足"
        duration_score = 60
    elif avg_duration <= 9:
        duration_status = "正常"
        duration_score = 100
    elif avg_duration <= 10:
        duration_status = "偏长"
        duration_score = 80
    else:
        duration_status = "过长"
        duration_score = 60

    sleep_duration_status = {
        "avg_duration": round(avg_duration, 1),
        "status": duration_status,
        "recommended_range": "7-9小时",
        "score": duration_score
    }

    # 睡眠质量分析
    quality_counts = {"good": 0, "fair": 0, "poor": 0}
    for log in recent_logs:
        quality = log.get("sleep_quality", "fair")
        if quality in quality_counts:
            quality_counts[quality] += 1

    total_nights = len(recent_logs)
    good_ratio = quality_counts["good"] / total_nights if total_nights > 0 else 0
    poor_ratio = quality_counts["poor"] / total_nights if total_nights > 0 else 0

    if good_ratio >= 0.7:
        quality_status = "优秀"
        quality_score = 100
    elif good_ratio >= 0.5:
        quality_status = "良好"
        quality_score = 80
    elif poor_ratio < 0.3:
        quality_status = "一般"
        quality_score = 60
    else:
        quality_status = "较差"
        quality_score = 40

    sleep_quality_status = {
        "good_nights": quality_counts["good"],
        "fair_nights": quality_counts["fair"],
        "poor_nights": quality_counts["poor"],
        "good_ratio": round(good_ratio * 100, 1),
        "status": quality_status,
        "score": quality_score
    }

    # 睡眠问题识别
    sleep_problems = []

    # 问题1：入睡困难
    sleep_latencies = [log.get("sleep_latency", 0) for log in recent_logs if log.get("sleep_latency") is not None]
    if sleep_latencies:
        avg_latency = sum(sleep_latencies) / len(sleep_latencies)
        long_latency_count = sum(1 for lat in sleep_latencies if lat > 30)

        if long_latency_count >= len(sleep_latencies) * 0.3:
            sleep_problems.append({
                "problem": "入睡困难",
                "severity": "中度" if long_latency_count >= len(sleep_latencies) * 0.5 else "轻度",
                "description": f"平均入睡时间 {round(avg_latency, 1)} 分钟，{long_latency_count} 晚超过30分钟"
            })

    # 问题2：夜间觉醒
    awakenings = [log.get("awakenings", 0) for log in recent_logs if log.get("awakenings") is not None]
    if awakenings:
        avg_awakenings = sum(awakenings) / len(awakenings)
        frequent_awakening_count = sum(1 for awk in awakenings if awk > 2)

        if avg_awakenings > 2 or frequent_awakening_count >= len(awakenings) * 0.3:
            sleep_problems.append({
                "problem": "睡眠维持困难",
                "severity": "中度" if avg_awakenings > 3 else "轻度",
                "description": f"平均每晚觉醒 {round(avg_awakenings, 1)} 次"
            })

    # 问题3：睡眠不足
    if avg_duration < 7:
        sleep_problems.append({
            "problem": "睡眠时长不足",
            "severity": "重度" if avg_duration < 6 else "中度",
            "description": f"平均睡眠时长 {round(avg_duration, 1)} 小时，低于推荐的7-9小时"
        })

    # 问题4：睡眠质量差
    if poor_ratio > 0.3:
        sleep_problems.append({
            "problem": "睡眠质量差",
            "severity": "重度" if poor_ratio > 0.5 else "中度",
            "description": f"{round(poor_ratio * 100, 1)}% 的夜晚睡眠质量差"
        })

    # 问题5：作息不规律
    bedtimes = []
    for log in recent_logs:
        bedtime_str = log.get("bedtime", "")
        if bedtime_str and ":" in bedtime_str:
            try:
                hour, minute = map(int, bedtime_str.split(":"))
                bedtime_minutes = hour * 60 + minute
                bedtimes.append(bedtime_minutes)
            except:
                pass

    if len(bedtimes) >= 7:
        # 计算标准差
        mean_bedtime = sum(bedtimes) / len(bedtimes)
        variance = sum((bt - mean_bedtime) ** 2 for bt in bedtimes) / len(bedtimes)
        std_dev = variance ** 0.5

        if std_dev > 60:  # 标准差超过60分钟
            sleep_problems.append({
                "problem": "作息不规律",
                "severity": "中度" if std_dev > 90 else "轻度",
                "description": f"上床时间波动较大（标准差 {round(std_dev, 1)} 分钟）"
            })

    # 趋势分析（如果请求）
    trend_analysis = {}
    if analysis_type in ["trend", "comprehensive"] and len(recent_logs) >= 14:
        # 计算最近7天和之前7天的对比
        recent_7 = recent_logs[-7:]
        previous_7 = recent_logs[-14:-7]

        recent_avg_duration = sum(log.get("sleep_duration", 0) for log in recent_7) / 7
        previous_avg_duration = sum(log.get("sleep_duration", 0) for log in previous_7) / 7

        duration_change = recent_avg_duration - previous_avg_duration
        duration_change_pct = (duration_change / previous_avg_duration * 100) if previous_avg_duration > 0 else 0

        recent_good_ratio = sum(1 for log in recent_7 if log.get("sleep_quality") == "good") / 7
        previous_good_ratio = sum(1 for log in previous_7 if log.get("sleep_quality") == "good") / 7
        quality_change = recent_good_ratio - previous_good_ratio

        trend_analysis = {
            "duration_trend": {
                "recent_avg": round(recent_avg_duration, 1),
                "previous_avg": round(previous_avg_duration, 1),
                "change": round(duration_change, 1),
                "change_percent": round(duration_change_pct, 1),
                "trend": "改善" if duration_change > 0.5 else ("恶化" if duration_change < -0.5 else "稳定")
            },
            "quality_trend": {
                "recent_good_ratio": round(recent_good_ratio * 100, 1),
                "previous_good_ratio": round(previous_good_ratio * 100, 1),
                "change": round(quality_change * 100, 1),
                "trend": "改善" if quality_change > 0.1 else ("恶化" if quality_change < -0.1 else "稳定")
            }
        }

    # 生成个性化建议
    recommendations = []

    # 基于睡眠时长的建议
    if avg_duration < 7:
        recommendations.append({
            "category": "睡眠时长",
            "priority": "高",
            "suggestion": f"增加睡眠时长至7-9小时。建议提前 {round(7 - avg_duration, 1)} 小时上床，或推迟起床时间。"
        })

    # 基于入睡困难的建议
    if any(p["problem"] == "入睡困难" for p in sleep_problems):
        recommendations.append({
            "category": "入睡改善",
            "priority": "高",
            "suggestion": "建立睡前例行程序：睡前1小时避免屏幕、进行放松活动（阅读、冥想、温水浴），保持卧室凉爽黑暗安静。"
        })

    # 基于夜间觉醒的建议
    if any(p["problem"] == "睡眠维持困难" for p in sleep_problems):
        recommendations.append({
            "category": "睡眠维持",
            "priority": "中",
            "suggestion": "减少睡前液体摄入，避免咖啡因和酒精。如果夜间醒来超过20分钟无法入睡，起床进行安静活动直到困倦。"
        })

    # 基于作息不规律的建议
    if any(p["problem"] == "作息不规律" for p in sleep_problems):
        recommendations.append({
            "category": "作息规律",
            "priority": "高",
            "suggestion": "固定上床和起床时间（包括周末），帮助调节生物钟。建议每天同一时间起床，即使睡眠不足。"
        })

    # 基于睡眠质量的建议
    if quality_status in ["较差", "一般"]:
        recommendations.append({
            "category": "睡眠质量",
            "priority": "中",
            "suggestion": "优化睡眠环境：保持卧室温度18-22°C，使用遮光窗帘，减少噪音。白天增加光照和运动，但避免睡前3小时剧烈运动。"
        })

    # 通用建议
    if not recommendations:
        recommendations.append({
            "category": "睡眠维护",
            "priority": "低",
            "suggestion": "保持良好睡眠习惯：规律作息、适度运动、避免睡前咖啡因和酒精、保持舒适睡眠环境。"
        })

    # 计算综合睡眠评分
    sleep_score = int((duration_score + quality_score) / 2)

    # 根据问题严重程度调整评分
    for problem in sleep_problems:
        if problem["severity"] == "重度":
            sleep_score -= 15
        elif problem["severity"] == "中度":
            sleep_score -= 10
        elif problem["severity"] == "轻度":
            sleep_score -= 5

    sleep_score = max(0, min(100, sleep_score))

    return {
        "sleep_score": sleep_score,
        "sleep_duration_status": sleep_duration_status,
        "sleep_quality_status": sleep_quality_status,
        "sleep_problems": sleep_problems,
        "recommendations": recommendations,
        "trend_analysis": trend_analysis,
        "analysis_summary": f"分析了 {len(recent_logs)} 天的睡眠数据，综合评分 {sleep_score}/100，发现 {len(sleep_problems)} 个睡眠问题，生成 {len(recommendations)} 条建议。"
    }

def analyze_rehabilitation(rehabilitation_data, analysis_type="comprehensive", time_range=30):
    """
    分析康复训练数据，评估康复进展，识别改善模式并提供个性化康复建议。

    参数：
    - rehabilitation_data: 康复数据字典，包含：
      - assessments: 功能评估列表 [{"date": "YYYY-MM-DD", "rom": {...}, "muscle_strength": {...}, "balance": {...}, "pain": 0-10}, ...]
      - training_logs: 训练日志列表 [{"date": "YYYY-MM-DD", "exercises": [...], "completed": true/false, "pain_level": 0-10}, ...]
      - goals: 康复目标列表 [{"goal": "...", "target_date": "YYYY-MM-DD", "progress": 0-100, "status": "achieved/in_progress/delayed"}, ...]
      - stage: 当前康复阶段信息 {"stage_number": 1-4, "stage_name": "...", "start_date": "YYYY-MM-DD"}
    - analysis_type: 分析类型，可选 "progress"（进展）、"pain"（疼痛）、"compliance"（依从性）、"comprehensive"（综合，默认）
    - time_range: 分析时间范围（天数），默认 30 天

    返回：
    - rehabilitation_score: 康复进展综合评分（0-100）
    - functional_improvement: 功能改善状态
    - pain_analysis: 疼痛分析
    - training_compliance: 训练依从性
    - goal_achievement: 目标达成情况
    - stage_progress: 阶段进展
    - recommendations: 个性化建议列表
    """

    # 参数验证
    if not rehabilitation_data or not isinstance(rehabilitation_data, dict):
        return {
            "error": "rehabilitation_data 必须是包含康复数据的字典",
            "rehabilitation_score": 0,
            "functional_improvement": {},
            "pain_analysis": {},
            "training_compliance": {},
            "goal_achievement": {},
            "stage_progress": {},
            "recommendations": []
        }

    assessments = rehabilitation_data.get("assessments", [])
    training_logs = rehabilitation_data.get("training_logs", [])
    goals = rehabilitation_data.get("goals", [])
    stage = rehabilitation_data.get("stage", {})

    if not assessments and not training_logs:
        return {
            "error": "至少需要提供功能评估或训练日志数据",
            "rehabilitation_score": 0,
            "functional_improvement": {},
            "pain_analysis": {},
            "training_compliance": {},
            "goal_achievement": {},
            "stage_progress": {},
            "recommendations": []
        }

    # 限制分析范围
    recent_assessments = assessments[-time_range:] if len(assessments) > time_range else assessments
    recent_logs = training_logs[-time_range:] if len(training_logs) > time_range else training_logs

    # 功能改善分析
    functional_improvement = {}
    if len(assessments) >= 2:
        baseline = assessments[0]
        current = assessments[-1]

        # ROM（关节活动度）改善
        rom_improvement = {}
        if "rom" in baseline and "rom" in current:
            baseline_rom = baseline.get("rom", {})
            current_rom = current.get("rom", {})

            for joint, value in current_rom.items():
                if joint in baseline_rom:
                    baseline_value = baseline_rom[joint]
                    improvement = value - baseline_value
                    improvement_pct = (improvement / baseline_value * 100) if baseline_value > 0 else 0

                    rom_improvement[joint] = {
                        "baseline": baseline_value,
                        "current": value,
                        "improvement": round(improvement, 1),
                        "improvement_percent": round(improvement_pct, 1),
                        "status": "显著改善" if improvement_pct >= 20 else ("改善" if improvement_pct >= 10 else "轻微改善")
                    }

        # 肌力改善（MMT评分 0-5）
        muscle_improvement = {}
        if "muscle_strength" in baseline and "muscle_strength" in current:
            baseline_muscle = baseline.get("muscle_strength", {})
            current_muscle = current.get("muscle_strength", {})

            for muscle, value in current_muscle.items():
                if muscle in baseline_muscle:
                    baseline_value = baseline_muscle[muscle]
                    improvement = value - baseline_value

                    muscle_improvement[muscle] = {
                        "baseline": baseline_value,
                        "current": value,
                        "improvement": improvement,
                        "status": "显著改善" if improvement >= 2 else ("改善" if improvement >= 1 else "稳定")
                    }

        # 平衡功能改善
        balance_improvement = {}
        if "balance" in baseline and "balance" in current:
            baseline_balance = baseline.get("balance", {})
            current_balance = current.get("balance", {})

            for test, value in current_balance.items():
                if test in baseline_balance:
                    baseline_value = baseline_balance[test]
                    improvement = value - baseline_value
                    improvement_pct = (improvement / baseline_value * 100) if baseline_value > 0 else 0

                    balance_improvement[test] = {
                        "baseline": baseline_value,
                        "current": value,
                        "improvement": round(improvement, 1),
                        "improvement_percent": round(improvement_pct, 1),
                        "status": "显著改善" if improvement_pct >= 30 else ("改善" if improvement_pct >= 15 else "轻微改善")
                    }

        functional_improvement = {
            "rom_improvement": rom_improvement,
            "muscle_improvement": muscle_improvement,
            "balance_improvement": balance_improvement,
            "assessment_count": len(assessments),
            "overall_status": "良好" if (rom_improvement or muscle_improvement or balance_improvement) else "需加强"
        }

    # 疼痛分析
    pain_analysis = {}
    if assessments or training_logs:
        pain_scores = []

        # 从评估中获取疼痛评分
        for assessment in recent_assessments:
            if "pain" in assessment:
                pain_scores.append(assessment["pain"])

        # 从训练日志中获取疼痛评分
        for log in recent_logs:
            if "pain_level" in log:
                pain_scores.append(log["pain_level"])

        if pain_scores:
            avg_pain = sum(pain_scores) / len(pain_scores)

            # 疼痛趋势分析（如果有足够数据）
            pain_trend = "稳定"
            if len(pain_scores) >= 7:
                recent_pain = sum(pain_scores[-7:]) / 7
                previous_pain = sum(pain_scores[-14:-7]) / 7 if len(pain_scores) >= 14 else avg_pain

                if recent_pain < previous_pain - 1:
                    pain_trend = "改善"
                elif recent_pain > previous_pain + 1:
                    pain_trend = "加重"

            # 疼痛水平评估
            if avg_pain <= 2:
                pain_level = "轻微"
            elif avg_pain <= 4:
                pain_level = "轻度"
            elif avg_pain <= 6:
                pain_level = "中度"
            else:
                pain_level = "重度"

            pain_analysis = {
                "avg_pain": round(avg_pain, 1),
                "pain_level": pain_level,
                "pain_trend": pain_trend,
                "pain_score_count": len(pain_scores),
                "max_pain": max(pain_scores),
                "min_pain": min(pain_scores)
            }

    # 训练依从性分析
    training_compliance = {}
    if training_logs:
        total_planned = len(recent_logs)
        completed_count = sum(1 for log in recent_logs if log.get("completed", False))
        compliance_rate = (completed_count / total_planned * 100) if total_planned > 0 else 0

        if compliance_rate >= 90:
            compliance_status = "优秀"
        elif compliance_rate >= 75:
            compliance_status = "良好"
        elif compliance_rate >= 60:
            compliance_status = "一般"
        else:
            compliance_status = "需改进"

        training_compliance = {
            "total_planned": total_planned,
            "completed": completed_count,
            "compliance_rate": round(compliance_rate, 1),
            "compliance_status": compliance_status,
            "missed_sessions": total_planned - completed_count
        }

    # 目标达成分析
    goal_achievement = {}
    if goals:
        achieved_goals = [g for g in goals if g.get("status") == "achieved"]
        in_progress_goals = [g for g in goals if g.get("status") == "in_progress"]
        delayed_goals = [g for g in goals if g.get("status") == "delayed"]

        total_goals = len(goals)
        achievement_rate = (len(achieved_goals) / total_goals * 100) if total_goals > 0 else 0

        # 计算平均进度
        avg_progress = sum(g.get("progress", 0) for g in goals) / total_goals if total_goals > 0 else 0

        goal_achievement = {
            "total_goals": total_goals,
            "achieved": len(achieved_goals),
            "in_progress": len(in_progress_goals),
            "delayed": len(delayed_goals),
            "achievement_rate": round(achievement_rate, 1),
            "avg_progress": round(avg_progress, 1),
            "status": "优秀" if achievement_rate >= 80 else ("良好" if achievement_rate >= 60 else "需加强")
        }

    # 阶段进展分析
    stage_progress = {}
    if stage:
        stage_number = stage.get("stage_number", 1)
        stage_name = stage.get("stage_name", "未知阶段")

        # 根据功能改善和目标达成评估阶段进展
        stage_completion = 0
        if goal_achievement:
            stage_completion = goal_achievement.get("avg_progress", 0)

        # 评估是否准备进入下一阶段
        ready_for_next = False
        if stage_completion >= 80 and training_compliance.get("compliance_rate", 0) >= 75:
            if pain_analysis.get("avg_pain", 10) <= 3:
                ready_for_next = True

        stage_progress = {
            "current_stage": stage_number,
            "stage_name": stage_name,
            "stage_completion": round(stage_completion, 1),
            "ready_for_next_stage": ready_for_next,
            "recommendation": "可以考虑进入下一阶段" if ready_for_next else "继续当前阶段训练"
        }

    # 生成个性化建议
    recommendations = []

    # 基于功能改善的建议
    if functional_improvement:
        if functional_improvement.get("overall_status") == "需加强":
            recommendations.append({
                "category": "功能训练",
                "priority": "高",
                "suggestion": "功能改善不明显，建议增加训练频率或调整训练强度。咨询康复师评估训练计划。"
            })
        elif functional_improvement.get("overall_status") == "良好":
            recommendations.append({
                "category": "功能训练",
                "priority": "中",
                "suggestion": "功能改善良好，继续保持当前训练计划。注意循序渐进，避免过度训练。"
            })

    # 基于疼痛的建议
    if pain_analysis:
        if pain_analysis.get("pain_level") in ["重度", "中度"]:
            recommendations.append({
                "category": "疼痛管理",
                "priority": "高",
                "suggestion": f"疼痛水平{pain_analysis.get('pain_level')}，建议调整训练强度，增加休息时间。必要时咨询医生调整止痛方案。"
            })
        elif pain_analysis.get("pain_trend") == "加重":
            recommendations.append({
                "category": "疼痛管理",
                "priority": "高",
                "suggestion": "疼痛呈加重趋势，建议暂停高强度训练，评估疼痛原因。必要时就医检查。"
            })
        elif pain_analysis.get("pain_trend") == "改善":
            recommendations.append({
                "category": "疼痛管理",
                "priority": "低",
                "suggestion": "疼痛控制良好，继续当前疼痛管理策略。"
            })

    # 基于依从性的建议
    if training_compliance:
        if training_compliance.get("compliance_status") in ["需改进", "一般"]:
            recommendations.append({
                "category": "训练依从性",
                "priority": "高",
                "suggestion": f"训练依从性{training_compliance.get('compliance_status')}（{training_compliance.get('compliance_rate')}%），建议设置训练提醒，寻找训练伙伴，或调整训练时间以提高依从性。"
            })

    # 基于目标达成的建议
    if goal_achievement:
        if goal_achievement.get("delayed", 0) > 0:
            recommendations.append({
                "category": "目标管理",
                "priority": "中",
                "suggestion": f"有{goal_achievement.get('delayed')}个目标进度滞后，建议与康复师讨论调整目标或训练计划。"
            })

    # 基于阶段进展的建议
    if stage_progress:
        if stage_progress.get("ready_for_next_stage"):
            recommendations.append({
                "category": "阶段转换",
                "priority": "中",
                "suggestion": "当前阶段完成度高，建议咨询康复师评估是否可以进入下一阶段训练。"
            })

    # 通用建议
    if not recommendations:
        recommendations.append({
            "category": "康复维护",
            "priority": "低",
            "suggestion": "康复进展良好，继续保持规律训练，注意循序渐进，避免过度训练导致损伤。"
        })

    # 计算综合康复评分
    rehabilitation_score = 50  # 基础分

    # 功能改善加分
    if functional_improvement and functional_improvement.get("overall_status") == "良好":
        rehabilitation_score += 20

    # 疼痛控制加分
    if pain_analysis:
        if pain_analysis.get("pain_level") == "轻微":
            rehabilitation_score += 15
        elif pain_analysis.get("pain_level") == "轻度":
            rehabilitation_score += 10
        elif pain_analysis.get("pain_level") == "中度":
            rehabilitation_score += 5

    # 依从性加分
    if training_compliance:
        compliance_rate = training_compliance.get("compliance_rate", 0)
        if compliance_rate >= 90:
            rehabilitation_score += 15
        elif compliance_rate >= 75:
            rehabilitation_score += 10
        elif compliance_rate >= 60:
            rehabilitation_score += 5

    # 目标达成加分
    if goal_achievement:
        achievement_rate = goal_achievement.get("achievement_rate", 0)
        rehabilitation_score += int(achievement_rate * 0.1)

    rehabilitation_score = max(0, min(100, rehabilitation_score))

    return {
        "rehabilitation_score": rehabilitation_score,
        "functional_improvement": functional_improvement,
        "pain_analysis": pain_analysis,
        "training_compliance": training_compliance,
        "goal_achievement": goal_achievement,
        "stage_progress": stage_progress,
        "recommendations": recommendations,
        "analysis_summary": f"康复评分 {rehabilitation_score}/100，分析了 {len(recent_assessments)} 次评估和 {len(recent_logs)} 次训练，生成 {len(recommendations)} 条建议。"
    }

def analyze_fitness(fitness_data, analysis_type="comprehensive", time_range=90):
    """
    分析运动数据，识别运动模式，评估健身进展并提供个性化训练建议。

    参数：
    - fitness_data: 运动数据字典，包含：
      - exercise_logs: 运动日志列表 [{"date": "YYYY-MM-DD", "type": "running/cycling/strength/yoga",
                                      "duration": 分钟, "distance": 公里, "calories": 卡路里,
                                      "intensity": "low/medium/high", "heart_rate_avg": 次/分}, ...]
      - fitness_goals: 健身目标列表 [{"goal": "...", "target_value": 数值, "current_value": 数值, "unit": "..."}, ...]
      - body_metrics: 身体指标（可选）{"weight": [...], "body_fat": [...], "muscle_mass": [...]}
    - analysis_type: 分析类型，可选 "trend"（趋势）、"progress"（进步）、"habit"（习惯）、"comprehensive"（综合，默认）
    - time_range: 分析时间范围（天数），默认 90 天

    返回：
    - fitness_score: 健身综合评分（0-100）
    - exercise_trends: 运动趋势分析
    - progress_tracking: 进步追踪
    - habit_analysis: 运动习惯分析
    - goal_status: 目标达成状态
    - recommendations: 个性化建议列表
    """

    # 参数验证
    if not fitness_data or not isinstance(fitness_data, dict):
        return {
            "error": "fitness_data 必须是包含运动数据的字典",
            "fitness_score": 0,
            "exercise_trends": {},
            "progress_tracking": {},
            "habit_analysis": {},
            "goal_status": {},
            "recommendations": []
        }

    exercise_logs = fitness_data.get("exercise_logs", [])
    fitness_goals = fitness_data.get("fitness_goals", [])
    body_metrics = fitness_data.get("body_metrics", {})

    if not exercise_logs:
        return {
            "error": "至少需要提供运动日志数据",
            "fitness_score": 0,
            "exercise_trends": {},
            "progress_tracking": {},
            "habit_analysis": {},
            "goal_status": {},
            "recommendations": []
        }

    # 限制分析范围
    recent_logs = exercise_logs[-time_range:] if len(exercise_logs) > time_range else exercise_logs

    # 运动趋势分析
    exercise_trends = {}
    if len(recent_logs) >= 7:
        # 计算总运动量
        total_duration = sum(log.get("duration", 0) for log in recent_logs)
        total_calories = sum(log.get("calories", 0) for log in recent_logs)
        total_distance = sum(log.get("distance", 0) for log in recent_logs if log.get("distance"))

        # 计算平均值
        avg_duration_per_week = (total_duration / len(recent_logs)) * 7
        avg_calories_per_week = (total_calories / len(recent_logs)) * 7
        avg_distance_per_week = (total_distance / len(recent_logs)) * 7 if total_distance > 0 else 0

        # 运动频率
        exercise_days = len(recent_logs)
        weeks = len(recent_logs) / 7
        avg_frequency = exercise_days / weeks if weeks > 0 else 0

        # 趋势分析（如果有足够数据）
        duration_trend = "稳定"
        if len(recent_logs) >= 28:
            recent_duration = sum(log.get("duration", 0) for log in recent_logs[-14:]) / 14
            previous_duration = sum(log.get("duration", 0) for log in recent_logs[-28:-14]) / 14

            if recent_duration > previous_duration * 1.1:
                duration_trend = "上升"
            elif recent_duration < previous_duration * 0.9:
                duration_trend = "下降"

        # 强度分布
        intensity_counts = {"low": 0, "medium": 0, "high": 0}
        for log in recent_logs:
            intensity = log.get("intensity", "medium")
            if intensity in intensity_counts:
                intensity_counts[intensity] += 1

        total_exercises = len(recent_logs)
        intensity_distribution = {
            "low": round(intensity_counts["low"] / total_exercises * 100, 1) if total_exercises > 0 else 0,
            "medium": round(intensity_counts["medium"] / total_exercises * 100, 1) if total_exercises > 0 else 0,
            "high": round(intensity_counts["high"] / total_exercises * 100, 1) if total_exercises > 0 else 0
        }

        # 运动类型分布
        type_counts = {}
        for log in recent_logs:
            exercise_type = log.get("type", "unknown")
            type_counts[exercise_type] = type_counts.get(exercise_type, 0) + 1

        type_distribution = {
            ex_type: round(count / total_exercises * 100, 1)
            for ex_type, count in type_counts.items()
        }

        exercise_trends = {
            "avg_duration_per_week": round(avg_duration_per_week, 1),
            "avg_calories_per_week": round(avg_calories_per_week, 1),
            "avg_distance_per_week": round(avg_distance_per_week, 1),
            "avg_frequency": round(avg_frequency, 1),
            "duration_trend": duration_trend,
            "intensity_distribution": intensity_distribution,
            "type_distribution": type_distribution,
            "total_exercises": total_exercises
        }

    # 进步追踪
    progress_tracking = {}
    if len(exercise_logs) >= 10:
        # 按运动类型分组追踪进步
        type_progress = {}

        for exercise_type in ["running", "cycling", "strength"]:
            type_logs = [log for log in exercise_logs if log.get("type") == exercise_type]

            if len(type_logs) >= 5:
                # 取前5次和最近5次对比
                baseline_logs = type_logs[:5]
                recent_logs_type = type_logs[-5:]

                baseline_avg_duration = sum(log.get("duration", 0) for log in baseline_logs) / 5
                recent_avg_duration = sum(log.get("duration", 0) for log in recent_logs_type) / 5

                baseline_avg_distance = sum(log.get("distance", 0) for log in baseline_logs if log.get("distance")) / 5
                recent_avg_distance = sum(log.get("distance", 0) for log in recent_logs_type if log.get("distance")) / 5

                duration_improvement = recent_avg_duration - baseline_avg_duration
                duration_improvement_pct = (duration_improvement / baseline_avg_duration * 100) if baseline_avg_duration > 0 else 0

                distance_improvement = recent_avg_distance - baseline_avg_distance
                distance_improvement_pct = (distance_improvement / baseline_avg_distance * 100) if baseline_avg_distance > 0 else 0

                type_progress[exercise_type] = {
                    "baseline_duration": round(baseline_avg_duration, 1),
                    "current_duration": round(recent_avg_duration, 1),
                    "duration_improvement": round(duration_improvement, 1),
                    "duration_improvement_percent": round(duration_improvement_pct, 1),
                    "baseline_distance": round(baseline_avg_distance, 1),
                    "current_distance": round(recent_avg_distance, 1),
                    "distance_improvement": round(distance_improvement, 1),
                    "distance_improvement_percent": round(distance_improvement_pct, 1),
                    "status": "显著进步" if duration_improvement_pct >= 20 else ("进步" if duration_improvement_pct >= 10 else "稳定")
                }

        progress_tracking = type_progress

    # 运动习惯分析
    habit_analysis = {}
    if len(recent_logs) >= 14:
        # 计算运动一致性（每周运动天数的标准差）
        weeks_data = []
        for i in range(0, len(recent_logs), 7):
            week_logs = recent_logs[i:i+7]
            weeks_data.append(len(week_logs))

        if len(weeks_data) >= 2:
            mean_days = sum(weeks_data) / len(weeks_data)
            variance = sum((x - mean_days) ** 2 for x in weeks_data) / len(weeks_data)
            std_dev = variance ** 0.5

            # 一致性评分（标准差越小越一致）
            consistency_score = max(0, 100 - std_dev * 20)

            if consistency_score >= 80:
                consistency_status = "优秀"
            elif consistency_score >= 60:
                consistency_status = "良好"
            elif consistency_score >= 40:
                consistency_status = "一般"
            else:
                consistency_status = "需改进"

            habit_analysis = {
                "avg_days_per_week": round(mean_days, 1),
                "consistency_score": round(consistency_score, 1),
                "consistency_status": consistency_status,
                "std_deviation": round(std_dev, 2)
            }

    # 目标达成状态
    goal_status = {}
    if fitness_goals:
        achieved_goals = []
        in_progress_goals = []

        for goal in fitness_goals:
            goal_name = goal.get("goal", "")
            target_value = goal.get("target_value", 0)
            current_value = goal.get("current_value", 0)
            unit = goal.get("unit", "")

            if current_value >= target_value:
                achieved_goals.append(goal_name)
                progress = 100
            else:
                progress = (current_value / target_value * 100) if target_value > 0 else 0
                in_progress_goals.append({
                    "goal": goal_name,
                    "progress": round(progress, 1),
                    "current": current_value,
                    "target": target_value,
                    "unit": unit
                })

        goal_status = {
            "total_goals": len(fitness_goals),
            "achieved": len(achieved_goals),
            "in_progress": len(in_progress_goals),
            "achievement_rate": round(len(achieved_goals) / len(fitness_goals) * 100, 1) if fitness_goals else 0,
            "achieved_goals": achieved_goals,
            "in_progress_goals": in_progress_goals
        }

    # 生成个性化建议
    recommendations = []

    # 基于运动频率的建议
    if exercise_trends:
        avg_freq = exercise_trends.get("avg_frequency", 0)
        if avg_freq < 3:
            recommendations.append({
                "category": "运动频率",
                "priority": "高",
                "suggestion": f"当前每周运动{round(avg_freq, 1)}天，建议增加至每周至少3-5天，以达到WHO推荐的运动量。"
            })
        elif avg_freq >= 5:
            recommendations.append({
                "category": "运动频率",
                "priority": "低",
                "suggestion": f"运动频率优秀（每周{round(avg_freq, 1)}天），继续保持。注意安排充足休息日避免过度训练。"
            })

    # 基于运动时长的建议
    if exercise_trends:
        avg_duration = exercise_trends.get("avg_duration_per_week", 0)
        if avg_duration < 150:
            recommendations.append({
                "category": "运动时长",
                "priority": "高",
                "suggestion": f"当前每周运动{round(avg_duration, 1)}分钟，建议增加至每周至少150分钟中等强度有氧运动（WHO推荐）。"
            })
        elif avg_duration >= 300:
            recommendations.append({
                "category": "运动时长",
                "priority": "低",
                "suggestion": "运动时长充足，达到WHO推荐的高水平运动量。继续保持，注意监测身体恢复情况。"
            })

    # 基于强度分布的建议
    if exercise_trends and "intensity_distribution" in exercise_trends:
        intensity_dist = exercise_trends["intensity_distribution"]
        if intensity_dist["medium"] < 50:
            recommendations.append({
                "category": "运动强度",
                "priority": "中",
                "suggestion": "建议增加中等强度运动比例至50%以上，中等强度运动对心血管健康最有益。"
            })
        if intensity_dist["high"] > 30:
            recommendations.append({
                "category": "运动强度",
                "priority": "中",
                "suggestion": "高强度运动占比较高，注意安排充足恢复时间，避免过度训练和运动损伤。"
            })

    # 基于运动类型的建议
    if exercise_trends and "type_distribution" in exercise_trends:
        type_dist = exercise_trends["type_distribution"]
        if len(type_dist) == 1:
            recommendations.append({
                "category": "运动多样性",
                "priority": "中",
                "suggestion": "运动类型单一，建议增加运动多样性（如有氧+力量+柔韧性训练），以全面提升身体素质。"
            })

    # 基于习惯一致性的建议
    if habit_analysis:
        consistency_status = habit_analysis.get("consistency_status", "")
        if consistency_status in ["需改进", "一般"]:
            recommendations.append({
                "category": "运动习惯",
                "priority": "高",
                "suggestion": f"运动一致性{consistency_status}，建议固定每周运动时间和天数，培养规律运动习惯。"
            })

    # 通用建议
    if not recommendations:
        recommendations.append({
            "category": "运动维护",
            "priority": "低",
            "suggestion": "运动习惯良好，继续保持规律运动。注意循序渐进，避免运动损伤，定期调整训练计划。"
        })

    # 计算综合健身评分
    fitness_score = 50  # 基础分

    # 运动频率加分
    if exercise_trends:
        avg_freq = exercise_trends.get("avg_frequency", 0)
        if avg_freq >= 5:
            fitness_score += 20
        elif avg_freq >= 3:
            fitness_score += 15
        elif avg_freq >= 2:
            fitness_score += 10

    # 运动时长加分
    if exercise_trends:
        avg_duration = exercise_trends.get("avg_duration_per_week", 0)
        if avg_duration >= 300:
            fitness_score += 15
        elif avg_duration >= 150:
            fitness_score += 10
        elif avg_duration >= 75:
            fitness_score += 5

    # 运动一致性加分
    if habit_analysis:
        consistency_score = habit_analysis.get("consistency_score", 0)
        fitness_score += int(consistency_score * 0.15)

    # 目标达成加分
    if goal_status:
        achievement_rate = goal_status.get("achievement_rate", 0)
        fitness_score += int(achievement_rate * 0.1)

    fitness_score = max(0, min(100, fitness_score))

    return {
        "fitness_score": fitness_score,
        "exercise_trends": exercise_trends,
        "progress_tracking": progress_tracking,
        "habit_analysis": habit_analysis,
        "goal_status": goal_status,
        "recommendations": recommendations,
        "analysis_summary": f"健身评分 {fitness_score}/100，分析了 {len(recent_logs)} 次运动记录，生成 {len(recommendations)} 条建议。"
    }

def analyze_health_trends(health_data, analysis_type="comprehensive", time_range=90):
    """
    分析一段时间内健康数据的趋势和模式，识别变化、相关性，提供数据驱动的健康洞察。

    参数：
    - health_data: 健康数据字典，包含：
      - weight_records: 体重记录列表 [{"date": "YYYY-MM-DD", "weight": 公斤, "bmi": 数值}, ...]
      - symptom_records: 症状记录列表 [{"date": "YYYY-MM-DD", "symptoms": ["头痛", "疲劳"], "severity": 1-10}, ...]
      - lab_results: 化验结果列表 [{"date": "YYYY-MM-DD", "metrics": {"glucose": 数值, "cholesterol": 数值, ...}}, ...]
      - mood_records: 情绪记录列表 [{"date": "YYYY-MM-DD", "mood_score": 1-10, "sleep_hours": 数值}, ...]
      - medication_logs: 用药日志列表 [{"date": "YYYY-MM-DD", "medication": "药名", "taken": true/false}, ...]
    - analysis_type: 分析类型，可选 "weight"（体重）、"symptoms"（症状）、"labs"（化验）、
                     "mood"（情绪）、"medication"（用药）、"comprehensive"（综合，默认）
    - time_range: 分析时间范围（天数），默认 90 天

    返回：
    - health_trend_score: 健康趋势综合评分（0-100，越高越好）
    - weight_trend: 体重/BMI 趋势分析
    - symptom_patterns: 症状模式分析
    - lab_trends: 化验结果趋势
    - mood_sleep_correlation: 情绪与睡眠相关性
    - medication_compliance: 用药依从性
    - change_alerts: 显著变化警报列表
    - recommendations: 数据驱动的建议列表
    """

    # 参数验证
    if not health_data or not isinstance(health_data, dict):
        return {
            "error": "health_data 必须是包含健康数据的字典",
            "health_trend_score": 0,
            "weight_trend": {},
            "symptom_patterns": {},
            "lab_trends": {},
            "mood_sleep_correlation": {},
            "medication_compliance": {},
            "change_alerts": [],
            "recommendations": []
        }

    weight_records = health_data.get("weight_records", [])
    symptom_records = health_data.get("symptom_records", [])
    lab_results = health_data.get("lab_results", [])
    mood_records = health_data.get("mood_records", [])
    medication_logs = health_data.get("medication_logs", [])

    # 检查是否有任何数据
    has_data = any([weight_records, symptom_records, lab_results, mood_records, medication_logs])
    if not has_data:
        return {
            "error": "至少需要提供一种健康数据（体重、症状、化验、情绪或用药记录）",
            "health_trend_score": 0,
            "weight_trend": {},
            "symptom_patterns": {},
            "lab_trends": {},
            "mood_sleep_correlation": {},
            "medication_compliance": {},
            "change_alerts": [],
            "recommendations": []
        }

    # 限制分析范围
    recent_weight = weight_records[-time_range:] if len(weight_records) > time_range else weight_records
    recent_symptoms = symptom_records[-time_range:] if len(symptom_records) > time_range else symptom_records
    recent_labs = lab_results[-time_range:] if len(lab_results) > time_range else lab_results
    recent_mood = mood_records[-time_range:] if len(mood_records) > time_range else mood_records
    recent_meds = medication_logs[-time_range:] if len(medication_logs) > time_range else medication_logs

    change_alerts = []

    # 体重/BMI 趋势分析
    weight_trend = {}
    if len(recent_weight) >= 2:
        weights = [r.get("weight", 0) for r in recent_weight if r.get("weight")]
        bmis = [r.get("bmi", 0) for r in recent_weight if r.get("bmi")]

        if weights:
            first_weight = weights[0]
            last_weight = weights[-1]
            weight_change = last_weight - first_weight
            weight_change_pct = (weight_change / first_weight * 100) if first_weight > 0 else 0

            # 趋势方向
            if weight_change_pct > 2:
                trend_direction = "上升"
            elif weight_change_pct < -2:
                trend_direction = "下降"
            else:
                trend_direction = "稳定"

            # 快速变化警报（超过5%）
            if abs(weight_change_pct) > 5:
                change_alerts.append({
                    "type": "体重变化",
                    "severity": "高" if abs(weight_change_pct) > 10 else "中",
                    "message": f"体重{trend_direction}{abs(round(weight_change, 1))}公斤（{abs(round(weight_change_pct, 1))}%），建议关注"
                })

            weight_trend = {
                "first_weight": first_weight,
                "last_weight": last_weight,
                "weight_change": round(weight_change, 1),
                "weight_change_percent": round(weight_change_pct, 1),
                "trend_direction": trend_direction,
                "data_points": len(weights)
            }

            if bmis:
                avg_bmi = sum(bmis) / len(bmis)
                last_bmi = bmis[-1]
                if last_bmi < 18.5:
                    bmi_status = "偏瘦"
                elif last_bmi < 24:
                    bmi_status = "正常"
                elif last_bmi < 28:
                    bmi_status = "超重"
                else:
                    bmi_status = "肥胖"

                weight_trend["avg_bmi"] = round(avg_bmi, 1)
                weight_trend["current_bmi"] = round(last_bmi, 1)
                weight_trend["bmi_status"] = bmi_status

                if last_bmi > 28 or last_bmi < 18.5:
                    change_alerts.append({
                        "type": "BMI 异常",
                        "severity": "中",
                        "message": f"当前 BMI {round(last_bmi, 1)}，状态：{bmi_status}，建议咨询医生"
                    })

    # 症状模式分析
    symptom_patterns = {}
    if recent_symptoms:
        # 统计症状频率
        symptom_freq = {}
        total_severity = 0
        severity_count = 0

        for record in recent_symptoms:
            symptoms = record.get("symptoms", [])
            severity = record.get("severity", 0)

            for symptom in symptoms:
                symptom_freq[symptom] = symptom_freq.get(symptom, 0) + 1

            if severity > 0:
                total_severity += severity
                severity_count += 1

        # 排序症状频率
        sorted_symptoms = sorted(symptom_freq.items(), key=lambda x: x[1], reverse=True)
        top_symptoms = sorted_symptoms[:5]

        avg_severity = total_severity / severity_count if severity_count > 0 else 0

        # 趋势分析（近期 vs 早期）
        symptom_trend = "稳定"
        if len(recent_symptoms) >= 14:
            recent_count = len(recent_symptoms[-7:])
            previous_count = len(recent_symptoms[-14:-7])
            if recent_count > previous_count * 1.3:
                symptom_trend = "加重"
                change_alerts.append({
                    "type": "症状加重",
                    "severity": "高",
                    "message": f"近7天症状记录增加，建议就医评估"
                })
            elif recent_count < previous_count * 0.7:
                symptom_trend = "改善"

        symptom_patterns = {
            "total_records": len(recent_symptoms),
            "unique_symptoms": len(symptom_freq),
            "top_symptoms": [{"symptom": s, "count": c} for s, c in top_symptoms],
            "avg_severity": round(avg_severity, 1),
            "symptom_trend": symptom_trend
        }

    # 化验结果趋势
    lab_trends = {}
    if len(recent_labs) >= 2:
        # 追踪各指标变化
        metric_history = {}
        for lab in recent_labs:
            metrics = lab.get("metrics", {})
            for metric, value in metrics.items():
                if metric not in metric_history:
                    metric_history[metric] = []
                metric_history[metric].append(value)

        # 参考范围（常见指标）
        reference_ranges = {
            "glucose": {"min": 70, "max": 100, "unit": "mg/dL"},
            "cholesterol": {"min": 0, "max": 200, "unit": "mg/dL"},
            "systolic_bp": {"min": 90, "max": 120, "unit": "mmHg"},
            "diastolic_bp": {"min": 60, "max": 80, "unit": "mmHg"},
            "hemoglobin": {"min": 12, "max": 17, "unit": "g/dL"}
        }

        metric_trends = {}
        for metric, values in metric_history.items():
            if len(values) >= 2:
                first_val = values[0]
                last_val = values[-1]
                change = last_val - first_val
                change_pct = (change / first_val * 100) if first_val > 0 else 0

                if change_pct > 5:
                    trend = "上升"
                elif change_pct < -5:
                    trend = "下降"
                else:
                    trend = "稳定"

                metric_info = {
                    "first_value": first_val,
                    "last_value": last_val,
                    "change": round(change, 2),
                    "change_percent": round(change_pct, 1),
                    "trend": trend
                }

                # 检查是否超出参考范围
                if metric in reference_ranges:
                    ref = reference_ranges[metric]
                    if last_val > ref["max"]:
                        metric_info["status"] = "偏高"
                        change_alerts.append({
                            "type": f"{metric} 偏高",
                            "severity": "中",
                            "message": f"{metric} 当前值 {last_val} {ref['unit']}，超出正常范围（{ref['min']}-{ref['max']}）"
                        })
                    elif last_val < ref["min"]:
                        metric_info["status"] = "偏低"
                        change_alerts.append({
                            "type": f"{metric} 偏低",
                            "severity": "中",
                            "message": f"{metric} 当前值 {last_val} {ref['unit']}，低于正常范围（{ref['min']}-{ref['max']}）"
                        })
                    else:
                        metric_info["status"] = "正常"

                metric_trends[metric] = metric_info

        lab_trends = {
            "metrics_tracked": len(metric_trends),
            "metric_details": metric_trends
        }

    # 情绪与睡眠相关性分析
    mood_sleep_correlation = {}
    if len(recent_mood) >= 7:
        mood_scores = [r.get("mood_score", 0) for r in recent_mood if r.get("mood_score")]
        sleep_hours = [r.get("sleep_hours", 0) for r in recent_mood if r.get("sleep_hours")]

        if mood_scores and sleep_hours and len(mood_scores) == len(sleep_hours):
            avg_mood = sum(mood_scores) / len(mood_scores)
            avg_sleep = sum(sleep_hours) / len(sleep_hours)

            # 简单皮尔逊相关系数
            n = len(mood_scores)
            if n >= 3:
                mean_mood = avg_mood
                mean_sleep = avg_sleep
                numerator = sum((mood_scores[i] - mean_mood) * (sleep_hours[i] - mean_sleep) for i in range(n))
                denom_mood = sum((x - mean_mood) ** 2 for x in mood_scores) ** 0.5
                denom_sleep = sum((x - mean_sleep) ** 2 for x in sleep_hours) ** 0.5
                correlation = numerator / (denom_mood * denom_sleep) if (denom_mood * denom_sleep) > 0 else 0

                if correlation > 0.5:
                    correlation_desc = "强正相关（睡眠越好，情绪越好）"
                elif correlation > 0.2:
                    correlation_desc = "弱正相关"
                elif correlation < -0.5:
                    correlation_desc = "强负相关"
                elif correlation < -0.2:
                    correlation_desc = "弱负相关"
                else:
                    correlation_desc = "无明显相关"
            else:
                correlation = 0
                correlation_desc = "数据不足"

            # 情绪趋势
            mood_trend = "稳定"
            if len(mood_scores) >= 14:
                recent_mood_avg = sum(mood_scores[-7:]) / 7
                previous_mood_avg = sum(mood_scores[-14:-7]) / 7
                if recent_mood_avg > previous_mood_avg + 0.5:
                    mood_trend = "改善"
                elif recent_mood_avg < previous_mood_avg - 0.5:
                    mood_trend = "下降"
                    if recent_mood_avg < 4:
                        change_alerts.append({
                            "type": "情绪持续低落",
                            "severity": "高",
                            "message": f"近7天平均情绪评分 {round(recent_mood_avg, 1)}/10，建议关注心理健康"
                        })

            mood_sleep_correlation = {
                "avg_mood_score": round(avg_mood, 1),
                "avg_sleep_hours": round(avg_sleep, 1),
                "correlation_coefficient": round(correlation, 2),
                "correlation_description": correlation_desc,
                "mood_trend": mood_trend,
                "data_points": n
            }

    # 用药依从性分析
    medication_compliance = {}
    if recent_meds:
        total_doses = len(recent_meds)
        taken_doses = sum(1 for log in recent_meds if log.get("taken", False))
        compliance_rate = (taken_doses / total_doses * 100) if total_doses > 0 else 0

        if compliance_rate >= 90:
            compliance_status = "优秀"
        elif compliance_rate >= 75:
            compliance_status = "良好"
        elif compliance_rate >= 60:
            compliance_status = "一般"
        else:
            compliance_status = "需改进"
            change_alerts.append({
                "type": "用药依从性低",
                "severity": "高",
                "message": f"用药依从率仅 {round(compliance_rate, 1)}%，漏服可能影响治疗效果"
            })

        # 按药物分类统计
        med_stats = {}
        for log in recent_meds:
            med_name = log.get("medication", "未知")
            if med_name not in med_stats:
                med_stats[med_name] = {"total": 0, "taken": 0}
            med_stats[med_name]["total"] += 1
            if log.get("taken", False):
                med_stats[med_name]["taken"] += 1

        med_compliance = {
            med: round(stats["taken"] / stats["total"] * 100, 1)
            for med, stats in med_stats.items()
        }

        medication_compliance = {
            "total_doses": total_doses,
            "taken_doses": taken_doses,
            "compliance_rate": round(compliance_rate, 1),
            "compliance_status": compliance_status,
            "per_medication": med_compliance
        }

    # 生成建议
    recommendations = []

    if weight_trend:
        if weight_trend.get("bmi_status") in ["超重", "肥胖"]:
            recommendations.append({
                "category": "体重管理",
                "priority": "高",
                "suggestion": f"BMI {weight_trend.get('current_bmi')}（{weight_trend.get('bmi_status')}），建议增加有氧运动，控制饮食热量，咨询营养师。"
            })
        elif weight_trend.get("trend_direction") == "下降" and weight_trend.get("weight_change_percent", 0) < -5:
            recommendations.append({
                "category": "体重管理",
                "priority": "中",
                "suggestion": "体重下降明显，如非主动减重，建议就医排查原因。"
            })

    if symptom_patterns:
        if symptom_patterns.get("symptom_trend") == "加重":
            recommendations.append({
                "category": "症状管理",
                "priority": "高",
                "suggestion": "症状频率增加，建议记录症状诱因，及时就医评估。"
            })
        if symptom_patterns.get("avg_severity", 0) > 6:
            recommendations.append({
                "category": "症状管理",
                "priority": "高",
                "suggestion": f"平均症状严重度 {symptom_patterns.get('avg_severity')}/10，建议就医评估治疗方案。"
            })

    if mood_sleep_correlation:
        if mood_sleep_correlation.get("avg_sleep_hours", 8) < 6:
            recommendations.append({
                "category": "睡眠改善",
                "priority": "高",
                "suggestion": f"平均睡眠 {mood_sleep_correlation.get('avg_sleep_hours')} 小时，低于推荐的7-9小时，建议改善睡眠习惯。"
            })
        if mood_sleep_correlation.get("mood_trend") == "下降":
            recommendations.append({
                "category": "心理健康",
                "priority": "高",
                "suggestion": "情绪评分呈下降趋势，建议关注心理健康，必要时寻求专业心理支持。"
            })

    if medication_compliance:
        if medication_compliance.get("compliance_status") in ["需改进", "一般"]:
            recommendations.append({
                "category": "用药依从性",
                "priority": "高",
                "suggestion": f"用药依从率 {medication_compliance.get('compliance_rate')}%，建议设置用药提醒，规律服药以保证治疗效果。"
            })

    if not recommendations:
        recommendations.append({
            "category": "健康维护",
            "priority": "低",
            "suggestion": "健康趋势总体良好，继续保持健康生活方式，定期监测各项健康指标。"
        })

    # 计算综合健康趋势评分
    health_trend_score = 60  # 基础分

    # 体重评分
    if weight_trend:
        bmi_status = weight_trend.get("bmi_status", "")
        if bmi_status == "正常":
            health_trend_score += 10
        elif bmi_status in ["超重", "肥胖"]:
            health_trend_score -= 10

    # 症状评分
    if symptom_patterns:
        if symptom_patterns.get("symptom_trend") == "改善":
            health_trend_score += 10
        elif symptom_patterns.get("symptom_trend") == "加重":
            health_trend_score -= 10

    # 情绪评分
    if mood_sleep_correlation:
        avg_mood = mood_sleep_correlation.get("avg_mood_score", 5)
        if avg_mood >= 7:
            health_trend_score += 10
        elif avg_mood < 4:
            health_trend_score -= 10

    # 用药依从性评分
    if medication_compliance:
        compliance_rate = medication_compliance.get("compliance_rate", 0)
        if compliance_rate >= 90:
            health_trend_score += 10
        elif compliance_rate < 60:
            health_trend_score -= 10

    # 警报扣分
    high_alerts = sum(1 for a in change_alerts if a.get("severity") == "高")
    health_trend_score -= high_alerts * 5

    health_trend_score = max(0, min(100, health_trend_score))

    return {
        "health_trend_score": health_trend_score,
        "weight_trend": weight_trend,
        "symptom_patterns": symptom_patterns,
        "lab_trends": lab_trends,
        "mood_sleep_correlation": mood_sleep_correlation,
        "medication_compliance": medication_compliance,
        "change_alerts": change_alerts,
        "recommendations": recommendations,
        "analysis_summary": f"健康趋势评分 {health_trend_score}/100，发现 {len(change_alerts)} 个变化警报，生成 {len(recommendations)} 条建议。"
    }

def analyze_health_ai(health_profile, health_metrics, analysis_mode="comprehensive", risk_models=None):
    """
    AI驱动的综合健康分析系统，整合多维度健康数据，识别异常模式，预测健康风险，提供个性化建议。

    参数：
    - health_profile: 用户基础档案字典，包含：
      - age: 年龄（岁）
      - gender: 性别（"male"/"female"）
      - height: 身高（厘米）
      - weight: 体重（公斤）
      - bmi: BMI（可选，自动计算）
      - activity_level: 活动水平（"sedentary"/"light"/"moderate"/"active"/"very_active"）
      - smoking: 是否吸烟（true/false）
      - family_history: 家族病史列表（如 ["hypertension", "diabetes"]）
    - health_metrics: 健康指标字典，包含：
      - vitals: 生命体征 {"systolic_bp": 数值, "diastolic_bp": 数值, "heart_rate": 数值, "glucose": 数值}
      - sleep: 睡眠数据 {"avg_hours": 数值, "quality_score": 1-10, "psqi_score": 0-21}
      - nutrition: 营养数据 {"calorie_intake": 数值, "protein_g": 数值, "fiber_g": 数值}
      - exercise: 运动数据 {"weekly_minutes": 数值, "intensity": "low/medium/high"}
      - mental_health: 心理健康 {"phq9_score": 0-27, "gad7_score": 0-21, "stress_level": 1-10}
    - analysis_mode: 分析模式，可选 "risk"（风险预测）、"anomaly"（异常检测）、
                     "correlation"（相关性）、"comprehensive"（综合，默认）
    - risk_models: 要运行的风险模型列表（可选），如 ["hypertension", "diabetes", "cardiovascular"]

    返回：
    - ai_health_score: AI综合健康评分（0-100）
    - risk_predictions: 各类疾病风险预测
    - anomaly_detection: 异常指标检测结果
    - correlation_insights: 健康指标相关性洞察
    - personalized_recommendations: 分级个性化建议（Level 1/2/3）
    - health_summary: AI健康摘要
    """

    # 参数验证
    if not health_profile or not isinstance(health_profile, dict):
        return {
            "error": "health_profile 必须是包含用户基础档案的字典",
            "ai_health_score": 0,
            "risk_predictions": {},
            "anomaly_detection": {},
            "correlation_insights": {},
            "personalized_recommendations": [],
            "health_summary": ""
        }

    if not health_metrics or not isinstance(health_metrics, dict):
        return {
            "error": "health_metrics 必须是包含健康指标的字典",
            "ai_health_score": 0,
            "risk_predictions": {},
            "anomaly_detection": {},
            "correlation_insights": {},
            "personalized_recommendations": [],
            "health_summary": ""
        }

    # 提取基础档案
    age = health_profile.get("age", 0)
    gender = health_profile.get("gender", "unknown")
    height = health_profile.get("height", 0)
    weight = health_profile.get("weight", 0)
    bmi = health_profile.get("bmi", 0)
    activity_level = health_profile.get("activity_level", "sedentary")
    smoking = health_profile.get("smoking", False)
    family_history = health_profile.get("family_history", [])

    # 自动计算 BMI
    if not bmi and height > 0 and weight > 0:
        bmi = weight / ((height / 100) ** 2)

    # 提取健康指标
    vitals = health_metrics.get("vitals", {})
    sleep = health_metrics.get("sleep", {})
    nutrition = health_metrics.get("nutrition", {})
    exercise = health_metrics.get("exercise", {})
    mental_health = health_metrics.get("mental_health", {})

    systolic_bp = vitals.get("systolic_bp", 0)
    diastolic_bp = vitals.get("diastolic_bp", 0)
    heart_rate = vitals.get("heart_rate", 0)
    glucose = vitals.get("glucose", 0)

    sleep_hours = sleep.get("avg_hours", 0)
    sleep_quality = sleep.get("quality_score", 0)
    psqi_score = sleep.get("psqi_score", 0)

    weekly_exercise = exercise.get("weekly_minutes", 0)
    exercise_intensity = exercise.get("intensity", "low")

    phq9_score = mental_health.get("phq9_score", 0)
    gad7_score = mental_health.get("gad7_score", 0)
    stress_level = mental_health.get("stress_level", 0)

    # 风险预测
    risk_predictions = {}
    models_to_run = risk_models if risk_models else ["hypertension", "diabetes", "cardiovascular", "sleep_disorder", "mental_health"]

    # 高血压风险（基于 Framingham 简化模型）
    if "hypertension" in models_to_run:
        hypertension_risk_score = 0

        if age >= 65:
            hypertension_risk_score += 3
        elif age >= 55:
            hypertension_risk_score += 2
        elif age >= 45:
            hypertension_risk_score += 1

        if systolic_bp >= 140 or diastolic_bp >= 90:
            hypertension_risk_score += 4
        elif systolic_bp >= 130 or diastolic_bp >= 80:
            hypertension_risk_score += 2

        if bmi >= 30:
            hypertension_risk_score += 2
        elif bmi >= 25:
            hypertension_risk_score += 1

        if smoking:
            hypertension_risk_score += 2

        if "hypertension" in family_history:
            hypertension_risk_score += 2

        if activity_level in ["sedentary", "light"]:
            hypertension_risk_score += 1

        if hypertension_risk_score >= 8:
            hypertension_risk = "高风险"
            hypertension_prob = 0.7
        elif hypertension_risk_score >= 5:
            hypertension_risk = "中风险"
            hypertension_prob = 0.4
        elif hypertension_risk_score >= 3:
            hypertension_risk = "低风险"
            hypertension_prob = 0.2
        else:
            hypertension_risk = "极低风险"
            hypertension_prob = 0.05

        risk_predictions["hypertension"] = {
            "risk_level": hypertension_risk,
            "probability": hypertension_prob,
            "risk_score": hypertension_risk_score,
            "key_factors": [
                f"年龄 {age} 岁",
                f"血压 {systolic_bp}/{diastolic_bp} mmHg" if systolic_bp else "血压未记录",
                f"BMI {round(bmi, 1)}" if bmi else "BMI 未计算",
                "吸烟" if smoking else None,
                "家族高血压史" if "hypertension" in family_history else None
            ],
            "model": "Framingham 简化模型"
        }
        risk_predictions["hypertension"]["key_factors"] = [f for f in risk_predictions["hypertension"]["key_factors"] if f]

    # 糖尿病风险（基于 ADA 风险评分）
    if "diabetes" in models_to_run:
        diabetes_risk_score = 0

        if age >= 60:
            diabetes_risk_score += 3
        elif age >= 50:
            diabetes_risk_score += 2
        elif age >= 40:
            diabetes_risk_score += 1

        if bmi >= 30:
            diabetes_risk_score += 3
        elif bmi >= 25:
            diabetes_risk_score += 2

        if glucose >= 100:
            diabetes_risk_score += 3
        elif glucose >= 90:
            diabetes_risk_score += 1

        if "diabetes" in family_history:
            diabetes_risk_score += 2

        if activity_level in ["sedentary", "light"]:
            diabetes_risk_score += 1

        if weekly_exercise < 150:
            diabetes_risk_score += 1

        if diabetes_risk_score >= 8:
            diabetes_risk = "高风险"
            diabetes_prob = 0.65
        elif diabetes_risk_score >= 5:
            diabetes_risk = "中风险"
            diabetes_prob = 0.35
        elif diabetes_risk_score >= 3:
            diabetes_risk = "低风险"
            diabetes_prob = 0.15
        else:
            diabetes_risk = "极低风险"
            diabetes_prob = 0.05

        risk_predictions["diabetes"] = {
            "risk_level": diabetes_risk,
            "probability": diabetes_prob,
            "risk_score": diabetes_risk_score,
            "key_factors": [
                f"年龄 {age} 岁",
                f"BMI {round(bmi, 1)}" if bmi else "BMI 未计算",
                f"空腹血糖 {glucose} mg/dL" if glucose else "血糖未记录",
                "家族糖尿病史" if "diabetes" in family_history else None,
                f"每周运动 {weekly_exercise} 分钟" if weekly_exercise else "运动数据未记录"
            ],
            "model": "ADA 糖尿病风险评分"
        }
        risk_predictions["diabetes"]["key_factors"] = [f for f in risk_predictions["diabetes"]["key_factors"] if f]

    # 心血管疾病风险（基于 ACC/AHA ASCVD 简化）
    if "cardiovascular" in models_to_run:
        cv_risk_score = 0

        if age >= 65:
            cv_risk_score += 4
        elif age >= 55:
            cv_risk_score += 3
        elif age >= 45:
            cv_risk_score += 2

        if systolic_bp >= 140:
            cv_risk_score += 3
        elif systolic_bp >= 130:
            cv_risk_score += 2

        if smoking:
            cv_risk_score += 3

        if bmi >= 30:
            cv_risk_score += 2

        if "cardiovascular" in family_history or "heart_disease" in family_history:
            cv_risk_score += 3

        if activity_level in ["sedentary", "light"]:
            cv_risk_score += 1

        if cv_risk_score >= 10:
            cv_risk = "高风险"
            cv_prob = 0.20
        elif cv_risk_score >= 6:
            cv_risk = "中风险"
            cv_prob = 0.10
        elif cv_risk_score >= 3:
            cv_risk = "低风险"
            cv_prob = 0.05
        else:
            cv_risk = "极低风险"
            cv_prob = 0.02

        risk_predictions["cardiovascular"] = {
            "risk_level": cv_risk,
            "probability": cv_prob,
            "risk_score": cv_risk_score,
            "key_factors": [
                f"年龄 {age} 岁",
                f"收缩压 {systolic_bp} mmHg" if systolic_bp else "血压未记录",
                "吸烟" if smoking else None,
                f"BMI {round(bmi, 1)}" if bmi else "BMI 未计算",
                "家族心血管病史" if ("cardiovascular" in family_history or "heart_disease" in family_history) else None
            ],
            "model": "ACC/AHA ASCVD 简化模型"
        }
        risk_predictions["cardiovascular"]["key_factors"] = [f for f in risk_predictions["cardiovascular"]["key_factors"] if f]

    # 睡眠障碍风险
    if "sleep_disorder" in models_to_run and sleep:
        sleep_risk_score = 0

        if sleep_hours < 6:
            sleep_risk_score += 3
        elif sleep_hours < 7:
            sleep_risk_score += 1

        if psqi_score >= 10:
            sleep_risk_score += 3
        elif psqi_score >= 6:
            sleep_risk_score += 2

        if sleep_quality and sleep_quality < 5:
            sleep_risk_score += 2

        if stress_level >= 7:
            sleep_risk_score += 1

        if sleep_risk_score >= 6:
            sleep_risk = "高风险"
        elif sleep_risk_score >= 3:
            sleep_risk = "中风险"
        else:
            sleep_risk = "低风险"

        risk_predictions["sleep_disorder"] = {
            "risk_level": sleep_risk,
            "risk_score": sleep_risk_score,
            "key_factors": [
                f"平均睡眠 {sleep_hours} 小时" if sleep_hours else "睡眠时长未记录",
                f"PSQI 评分 {psqi_score}" if psqi_score else "PSQI 未评估",
                f"睡眠质量 {sleep_quality}/10" if sleep_quality else "睡眠质量未记录"
            ],
            "model": "PSQI 睡眠质量评估"
        }

    # 心理健康风险
    if "mental_health" in models_to_run and mental_health:
        mh_risk_score = 0

        if phq9_score >= 15:
            mh_risk_score += 4
        elif phq9_score >= 10:
            mh_risk_score += 3
        elif phq9_score >= 5:
            mh_risk_score += 1

        if gad7_score >= 15:
            mh_risk_score += 3
        elif gad7_score >= 10:
            mh_risk_score += 2
        elif gad7_score >= 5:
            mh_risk_score += 1

        if stress_level >= 8:
            mh_risk_score += 2
        elif stress_level >= 6:
            mh_risk_score += 1

        if mh_risk_score >= 6:
            mh_risk = "高风险"
        elif mh_risk_score >= 3:
            mh_risk = "中风险"
        else:
            mh_risk = "低风险"

        risk_predictions["mental_health"] = {
            "risk_level": mh_risk,
            "risk_score": mh_risk_score,
            "key_factors": [
                f"PHQ-9 评分 {phq9_score}（{('无抑郁' if phq9_score < 5 else '轻度' if phq9_score < 10 else '中度' if phq9_score < 15 else '重度')}）" if phq9_score else "PHQ-9 未评估",
                f"GAD-7 评分 {gad7_score}" if gad7_score else "GAD-7 未评估",
                f"压力水平 {stress_level}/10" if stress_level else "压力未评估"
            ],
            "model": "PHQ-9 + GAD-7 评估"
        }

    # 异常检测（Z-score 方法）
    anomaly_detection = {}
    normal_ranges = {
        "systolic_bp": {"mean": 115, "std": 15, "unit": "mmHg", "label": "收缩压"},
        "diastolic_bp": {"mean": 75, "std": 10, "unit": "mmHg", "label": "舒张压"},
        "heart_rate": {"mean": 72, "std": 12, "unit": "次/分", "label": "心率"},
        "glucose": {"mean": 90, "std": 10, "unit": "mg/dL", "label": "血糖"},
        "bmi": {"mean": 22, "std": 3, "unit": "", "label": "BMI"},
        "sleep_hours": {"mean": 7.5, "std": 1, "unit": "小时", "label": "睡眠时长"}
    }

    check_values = {
        "systolic_bp": systolic_bp,
        "diastolic_bp": diastolic_bp,
        "heart_rate": heart_rate,
        "glucose": glucose,
        "bmi": bmi,
        "sleep_hours": sleep_hours
    }

    anomalies = []
    for metric, value in check_values.items():
        if value and value > 0 and metric in normal_ranges:
            ref = normal_ranges[metric]
            z_score = (value - ref["mean"]) / ref["std"]

            if abs(z_score) > 2:
                severity = "高" if abs(z_score) > 3 else "中"
                direction = "偏高" if z_score > 0 else "偏低"
                anomalies.append({
                    "metric": ref["label"],
                    "value": round(value, 1),
                    "unit": ref["unit"],
                    "z_score": round(z_score, 2),
                    "direction": direction,
                    "severity": severity
                })

    anomaly_detection = {
        "anomalies_found": len(anomalies),
        "anomaly_details": anomalies,
        "method": "Z-score 异常检测（|z| > 2）"
    }

    # 相关性洞察
    correlation_insights = []

    if sleep_hours and phq9_score:
        if sleep_hours < 6 and phq9_score >= 10:
            correlation_insights.append({
                "variables": ["睡眠时长", "抑郁评分"],
                "insight": "睡眠不足与抑郁症状同时存在，两者可能相互影响",
                "recommendation": "改善睡眠质量可能有助于缓解抑郁症状"
            })

    if weekly_exercise and systolic_bp:
        if weekly_exercise >= 150 and systolic_bp < 130:
            correlation_insights.append({
                "variables": ["运动量", "血压"],
                "insight": "规律运动与正常血压相关，运动对血压控制有积极作用",
                "recommendation": "继续保持规律运动习惯"
            })
        elif weekly_exercise < 75 and systolic_bp >= 130:
            correlation_insights.append({
                "variables": ["运动量", "血压"],
                "insight": "运动不足与血压偏高同时存在",
                "recommendation": "增加有氧运动可能有助于降低血压"
            })

    if bmi and glucose:
        if bmi >= 25 and glucose >= 100:
            correlation_insights.append({
                "variables": ["BMI", "血糖"],
                "insight": "超重与血糖偏高同时存在，代谢综合征风险增加",
                "recommendation": "控制体重有助于改善血糖代谢"
            })

    # 分级个性化建议
    personalized_recommendations = []

    # Level 1: 一般性建议
    if weekly_exercise < 150:
        personalized_recommendations.append({
            "level": 1,
            "category": "运动",
            "suggestion": f"当前每周运动 {weekly_exercise} 分钟，建议增加至每周至少150分钟中等强度有氧运动（WHO推荐）。",
            "evidence": "WHO 2020 身体活动指南"
        })

    if sleep_hours and sleep_hours < 7:
        personalized_recommendations.append({
            "level": 1,
            "category": "睡眠",
            "suggestion": f"当前平均睡眠 {sleep_hours} 小时，建议保持每晚7-9小时睡眠，固定作息时间。",
            "evidence": "美国睡眠医学学会推荐"
        })

    # Level 2: 参考性建议（基于个人数据）
    high_risk_conditions = [k for k, v in risk_predictions.items() if v.get("risk_level") in ["高风险", "中风险"]]
    if high_risk_conditions:
        for condition in high_risk_conditions[:2]:
            condition_names = {
                "hypertension": "高血压",
                "diabetes": "糖尿病",
                "cardiovascular": "心血管疾病",
                "sleep_disorder": "睡眠障碍",
                "mental_health": "心理健康问题"
            }
            personalized_recommendations.append({
                "level": 2,
                "category": "风险管理",
                "suggestion": f"基于您的个人数据，{condition_names.get(condition, condition)}风险为{risk_predictions[condition]['risk_level']}，建议关注相关预防措施。",
                "evidence": "基于个人健康数据分析"
            })

    # Level 3: 医疗建议（需医生确认）
    if anomaly_detection["anomalies_found"] > 0:
        high_anomalies = [a for a in anomaly_detection["anomaly_details"] if a["severity"] == "高"]
        if high_anomalies:
            personalized_recommendations.append({
                "level": 3,
                "category": "医疗评估",
                "suggestion": f"检测到 {len(high_anomalies)} 个高度异常指标（{', '.join([a['metric'] for a in high_anomalies])}），建议尽快就医进行专业评估。",
                "evidence": "Z-score 异常检测结果",
                "disclaimer": "本建议仅供参考，不构成医疗诊断，请咨询专业医生。"
            })

    if phq9_score >= 15 or gad7_score >= 15:
        personalized_recommendations.append({
            "level": 3,
            "category": "心理健康",
            "suggestion": f"PHQ-9 评分 {phq9_score} 或 GAD-7 评分 {gad7_score} 提示中重度心理健康问题，强烈建议寻求专业心理健康支持。",
            "evidence": "PHQ-9/GAD-7 临床评估标准",
            "disclaimer": "本建议仅供参考，不构成医疗诊断，请咨询专业医生。"
        })

    if not personalized_recommendations:
        personalized_recommendations.append({
            "level": 1,
            "category": "健康维护",
            "suggestion": "各项健康指标总体良好，继续保持健康生活方式，定期体检。",
            "evidence": "综合健康评估"
        })

    # 计算 AI 综合健康评分
    ai_health_score = 70  # 基础分

    # BMI 评分
    if bmi:
        if 18.5 <= bmi < 24:
            ai_health_score += 10
        elif bmi >= 30 or bmi < 18.5:
            ai_health_score -= 10
        elif bmi >= 25:
            ai_health_score -= 5

    # 血压评分
    if systolic_bp:
        if systolic_bp < 120 and diastolic_bp < 80:
            ai_health_score += 5
        elif systolic_bp >= 140 or diastolic_bp >= 90:
            ai_health_score -= 10

    # 运动评分
    if weekly_exercise >= 150:
        ai_health_score += 5
    elif weekly_exercise < 75:
        ai_health_score -= 5

    # 睡眠评分
    if sleep_hours:
        if 7 <= sleep_hours <= 9:
            ai_health_score += 5
        elif sleep_hours < 6:
            ai_health_score -= 5

    # 心理健康评分
    if phq9_score:
        if phq9_score < 5:
            ai_health_score += 5
        elif phq9_score >= 15:
            ai_health_score -= 10

    # 异常扣分
    ai_health_score -= anomaly_detection["anomalies_found"] * 3

    # 高风险扣分
    high_risk_count = sum(1 for v in risk_predictions.values() if v.get("risk_level") == "高风险")
    ai_health_score -= high_risk_count * 5

    ai_health_score = max(0, min(100, ai_health_score))

    # 生成健康摘要
    risk_summary = []
    for condition, pred in risk_predictions.items():
        if pred.get("risk_level") in ["高风险", "中风险"]:
            condition_names = {
                "hypertension": "高血压",
                "diabetes": "糖尿病",
                "cardiovascular": "心血管疾病",
                "sleep_disorder": "睡眠障碍",
                "mental_health": "心理健康"
            }
            risk_summary.append(f"{condition_names.get(condition, condition)}（{pred['risk_level']}）")

    health_summary = f"AI综合健康评分 {ai_health_score}/100。"
    if risk_summary:
        health_summary += f" 需关注风险：{', '.join(risk_summary)}。"
    if anomaly_detection["anomalies_found"] > 0:
        health_summary += f" 检测到 {anomaly_detection['anomalies_found']} 个异常指标。"
    health_summary += f" 共生成 {len(personalized_recommendations)} 条个性化建议。"
    health_summary += " [仅供参考，不构成医疗诊断]"

    return {
        "ai_health_score": ai_health_score,
        "risk_predictions": risk_predictions,
        "anomaly_detection": anomaly_detection,
        "correlation_insights": correlation_insights,
        "personalized_recommendations": personalized_recommendations,
        "health_summary": health_summary
    }
